INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1, 'Capítulo', NULL, 1, 'Varios', 'Nota. 1. Este Capítulo comprende todos los animales vivos, excepto: a) los peces, los crustáceos, moluscos y demás invertebrados acuáticos, de las partidas 03.01, 03.06, 03.07 o 03.08; b) los cultivos de microorganismos y demás productos de la partida 30.02; c) los animales de la partida 95.08. Notas Complementarias: 1. En la subpartida 0102.2 la expresión “bovinos domésticos” comprende los animales de las especies “Bos primigenius Taurus (Bos Taurus)” y “Bos primigenius Indicus (Bos Indicus)”. 2. En las subpartidas 0105.94.00.10 y 0105.99.00.10, la expresión “especímenes de interés genético”, comprende los animales considerados como tales por la autoridad nacional con competencia en materia de agricultura. 8 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (2, 'Capítulo', NULL, 2, 'Varios', 'Nota. 1. Este Capítulo no comprende: a) respecto de las partidas 02.01 a 02.08 y 02.10, los productos impropios para la alimentación humana; b) los insectos comestibles, sin vida (partida 04.10); c) las tripas, vejigas y estómagos de animales (partida 05.04), ni la sangre animal (partidas 05.11 o 30.02); d) las grasas animales, excepto los productos de la partida 02.09 (Capítulo 15). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 9', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (3, 'Capítulo', NULL, 3, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los mamíferos de la partida 01.06; b) la carne de los mamíferos de la partida 01.06 (partidas 02.08 o 02.10); c) el pescado (incluidos los hígados, huevas y lechas) ni los crustáceos, moluscos o demás invertebrados acuáticos, muertos e impropios para la alimentación humana por su naturaleza o por su estado de presentación (Capítulo 5); la harina, polvo y «pellets» de pescado o de crustáceos, moluscos o demás invertebrados acuáticos, impropios para la alimentación humana (partida 23.01); d) el caviar y los sucedáneos del caviar preparados con huevas de pescado (partida 16.04). 2. En este Capítulo, el término «pellets» designa los productos en forma de cilindro, bolita, etc., aglomerados por simple presión o con adición de una pequeña cantidad de aglutinante. 3. Las partidas 03.05 a 03.08 no comprenden la harina, polvo y «pellets», aptos para la alimentación humana (partida 03.09). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 11', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (4, 'Capítulo', NULL, 4, 'Varios', 'Notas. 1. Se considera leche, la leche entera y la leche desnatada (descremada) total o parcialmente. 2. En la partida 04.03, el yogur puede estar concentrado o aromatizado o con adición de azúcar u otro edulcorante, con frutas u otros frutos, cacao, chocolate, especias, café o extractos de café, plantas, partes de plantas, cereales o productos de panadería, siempre que cualquier sustancia añadida no se utilice para sustituir, en todo o en parte, cualquier componente de la leche, y el producto conserve el carácter esencial de yogur. 3. En la partida 04.05: a) Se entiende por manteca (mantequilla)*, la manteca (mantequilla)* natural, la manteca (mantequilla)* del lactosuero o la manteca (mantequilla)* «recombinada» (fresca, salada o rancia, incluso en recipientes herméticamente cerrados) que provengan exclusivamente de la leche, con un contenido de materias grasas de la leche que sea superior o igual al 80 % pero inferior o igual al 95 %, en peso, de materias sólidas de la leche, inferior o igual al 2 % en peso y, de agua, inferior o igual al 16 % en peso. La manteca (mantequilla)* no debe contener emulsionantes añadidos pero puede contener cloruro sódico, colorantes alimentarios, sales de neutralización y cultivos de bacterias lácticas inocuas. b) Se entiende por pastas lácteas para untar las emulsiones del tipo agua-en-aceite que se puedan untar y contengan materias grasas de la leche como únicas materias grasas y en las que el contenido de éstas sea superior o igual al 39 % pero inferior al 80 %, en peso. 4. Los productos obtenidos por concentración del lactosuero con adición de leche o de materias grasas de la leche se clasifican en la partida 04.06 como quesos, siempre que presenten las tres características siguientes: a) un contenido de materias grasas de la leche superior o igual al 5 %, calculado en peso sobre el extracto seco; b) un contenido de extracto seco superior o igual al 70 % pero inferior o igual al 85 %, calculado en peso; c) moldeados o susceptibles de serlo. 5. Este Capítulo no comprende: a) los insectos sin vida, impropios para la alimentación humana (partida 05.11); b) los productos obtenidos del lactosuero, con un contenido de lactosa superior al 95 % en peso, expresado en lactosa anhidra, calculado sobre materia seca (partida 17.02); c) los productos resultantes de la sustitución en la leche de uno o varios de sus componentes naturales (por ejemplo, materia grasa de tipo butírico) por otra sustancia (por ejemplo, materia grasa de tipo oleico) (partidas 19.01 o 21.06); d) las albúminas (incluidos los concentrados de varias proteínas del lactosuero, con un contenido de proteínas del lactosuero superior al 80 % en peso, calculado sobre materia seca) (partida 35.02) ni las globulinas (partida 35.04). 6. En la partida 04.10, el término insectos se refiere a insectos comestibles, sin vida, enteros o en trozos, frescos, refrigerados, congelados, secos, ahumados, salados o en salmuera, así como la harina y polvo, de insectos, aptos para la alimentación humana. Sin embargo, este término no comprende los insectos comestibles, sin vida, preparados o conservados de otro modo (Sección IV, generalmente). Notas de subpartida. 1. En la subpartida 0404.10, se entiende por lactosuero modificado el producto constituido por componentes del lactosuero, es decir, lactosuero del que se haya extraído, total o parcialmente, lactosa, proteínas o sales minerales, o al que se haya añadido componentes naturales del lactosuero, así como los productos obtenidos por mezcla de componentes naturales del lactosuero. 2. En la subpartida 0405.10, el término manteca (mantequilla)* no comprende la manteca (mantequilla) deshidratada ni la «ghee» (subpartida 0405.90). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 21', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (5, 'Capítulo', NULL, 5, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los productos comestibles, excepto las tripas, vejigas y estómagos de animales, enteros o en trozos, y la sangre animal (líquida o desecada); b) los cueros, pieles y peletería, excepto los productos de la partida 05.05 y los recortes y desperdicios similares de pieles en bruto de la partida 05.11 (Capítulos 41 o 43); c) las materias primas textiles de origen animal, excepto la crin y los desperdicios de crin (Sección XI); d) las cabezas preparadas para artículos de cepillería (partida 96.03). 2. En la partida 05.01 también se considera cabello en bruto el extendido longitudinalmente pero sin colocarlo en el mismo sentido. 3. En la Nomenclatura, se considera marfil la materia de las defensas de elefante, hipopótamo, morsa, narval o jabalí y los cuernos de rinoceronte, así como los dientes de todos los animales. 4. En la Nomenclatura, se considera crin tanto el pelo de la crin como el de la cola de los équidos o de los bóvidos. La partida 05.11 comprende, entre otros, la crin y sus desperdicios, incluso en napas con o sin soporte. 24 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (6, 'Capítulo', NULL, 6, 'Varios', 'Notas. 1. Salvo lo dispuesto en la segunda parte de la partida 06.01, este Capítulo comprende únicamente los productos suministrados habitualmente por los horticultores, viveristas o floristas para la plantación o la ornamentación. Sin embargo, se excluyen de este Capítulo las papas (patatas)*, cebollas hortenses, chalotes, ajos y demás productos del Capítulo 7. 2. Los ramos, cestas, coronas y artículos similares se asimilan a las flores o follajes de las partidas 06.03 o 06.04, sin tener en cuenta los accesorios de otras materias. Sin embargo, estas partidas no comprenden los collages y cuadros similares de la partida 97.01. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 25', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (7, 'Capítulo', NULL, 7, 'Varios', 'Notas. 1. Este Capítulo no comprende los productos forrajeros de la partida 12.14. 2. En las partidas 07.09, 07.10, 07.11 y 07.12, la expresión hortalizas alcanza también a los hongos comestibles, trufas, aceitunas, alcaparras, calabacines (zapallitos), calabazas (zapallos), berenjenas, maíz dulce (Zea mays var. saccharata), frutos de los géneros Capsicum o Pimenta, hinojo y plantas como el perejil, perifollo, estragón, berro y mejorana cultivada (Majorana hortensis u Origanum majorana). 3. La partida 07.12 comprende todas las hortalizas secas de las especies clasificadas en las partidas 07.01 a 07.11, excepto: a) las hortalizas de vaina secas desvainadas (partida 07.13); b) el maíz dulce en las formas especificadas en las partidas 11.02 a 11.04; c) la harina, sémola, polvo, copos, gránulos y «pellets», de papa (patata)* (partida 11.05); d) la harina, sémola y polvo de hortalizas de vaina secas de la partida 07.13 (partida 11.06). 4. Los frutos de los géneros Capsicum o Pimenta, secos, triturados o pulverizados, se excluyen, sin embargo, de este Capítulo (partida 09.04). 5. La partida 07.11 comprende las hortalizas que se hayan sometido a un tratamiento con el único fin de que sean conservadas provisionalmente durante el transporte y almacenamiento antes de su utilización (por ejemplo: con gas sulfuroso o con agua salada, sulfurosa o adicionada de otras sustancias para asegurar provisionalmente dicha conservación), siempre que, en este estado, sean impropias para consumo inmediato. 26 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (8, 'Capítulo', NULL, 8, 'Varios', 'Notas. 1. Este Capítulo no comprende los frutos no comestibles. 2. Las frutas y otros frutos refrigerados se clasifican en las mismas partidas que las frutas y frutos frescos correspondientes. 3. Las frutas y otros frutos secos de este Capítulo pueden estar parcialmente rehidratados o tratados para los fines siguientes: a) mejorar su conservación o estabilidad (por ejemplo: mediante tratamiento térmico moderado, sulfurado, adición de ácido sórbico o de sorbato de potasio); b) mejorar o mantener su aspecto (por ejemplo: por adición de aceite vegetal o pequeñas cantidades de jarabe de glucosa), siempre que conserven el carácter de frutas o frutos secos. 4. La partida 08.12 comprende las frutas y otros frutos que se hayan sometido a un tratamiento con el único fin de que sean conservados provisionalmente durante su transporte y almacenamiento antes de su utilización (por ejemplo: con gas sulfuroso o con agua salada, sulfurosa o adicionada de otras sustancias para asegurar provisionalmente dicha conservación), siempre que, en este estado, sean impropios para consumo inmediato. 28 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (9, 'Capítulo', NULL, 9, 'Varios', 'Notas. 1. Las mezclas entre sí de los productos de las partidas 09.04 a 09.10 se clasifican como sigue: a) las mezclas entre sí de productos de una misma partida se clasifican en dicha partida; b) las mezclas entre sí de productos de distintas partidas se clasifican en la partida 09.10. El hecho de que se añadan otras sustancias a los productos comprendidos en las partidas 09.04 a 09.10 (incluidas las mezclas citadas en los apartados a) o b) anteriores) no influye en su clasificación, siempre que las mezclas así obtenidas conserven el carácter esencial de los productos citados en cada una de estas partidas. Por el contrario, dichas mezclas se excluyen de este Capítulo y se clasifican en la partida 21.03 si constituyen condimentos o sazonadores compuestos. 2. Este Capítulo no comprende la pimienta de Cubeba (Piper cubeba) ni los demás productos de la partida 12.11. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 31', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (10, 'Capítulo', NULL, 10, 'Varios', 'Notas. 1. A) Los productos citados en los textos de las partidas de este Capítulo se clasifican en dichas partidas solo si están presentes los granos, incluso en espigas o con los tallos. B) Este Capítulo no comprende los granos mondados o trabajados de otra forma. Sin embargo, el arroz descascarillado, blanqueado, pulido, glaseado, escaldado o partido se clasifica en la partida 10.06. Asimismo, la quinoa (quinua)* a la cual se le ha eliminado total o parcialmente el pericarpio a fin de separar la saponina, pero que no haya sido sometida a ningún otro trabajo, permanece clasificada en la partida 10.08. 2. La partida 10.05 no comprende el maíz dulce (Capítulo 7). Nota de subpartida. 1. Se considera trigo duro el de la especie Triticum durum y los híbridos derivados del cruce interespecífico del Triticum durum que tengan 28 cromosomas como aquél. 32 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (11, 'Capítulo', NULL, 11, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) la malta tostada acondicionada como sucedáneo del café (partidas 09.01 o 21.01, según los casos); b) la harina, grañones, sémola, almidón y fécula preparados, de la partida 19.01; c) las hojuelas o copos de maíz y demás productos de la partida 19.04; d) las hortalizas preparadas o conservadas de las partidas 20.01, 20.04 o 20.05; e) los productos farmacéuticos (Capítulo 30); f) el almidón y la fécula que tengan el carácter de preparaciones de perfumería, de tocador o de cosmética (Capítulo 33). 2. A) Los productos de la molienda de los cereales designados en el cuadro siguiente se clasifican en este Capítulo, si tienen simultáneamente en peso sobre producto seco: a) un contenido de almidón (determinado según el método polarimétrico Ewers modificado) superior al indicado en la columna (2); b) un contenido de cenizas (deduciendo las materias minerales que hayan podido añadirse) inferior o igual al indicado en la columna (3). Los que no cumplan las condiciones anteriores se clasifican en la partida 23.02. Sin embargo, el germen de cereales entero, aplastado, en copos o molido, siempre se clasificará en la partida 11.04. B) Los productos incluidos en este Capítulo, en virtud de las disposiciones anteriores, se clasifican en las partidas 11.01 u 11.02 cuando el porcentaje en peso que pase por un tamiz de tela metálica con abertura de malla correspondiente a la indicada en las columnas (4) o (5), según los casos, sea superior o igual al indicado para cada cereal. En caso contrario, se clasifican en las partidas 11.03 u 11.04. Cereal', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (12, 'Capítulo', NULL, 12, 'Varios', 'Notas. 1. La nuez y la almendra de palma (palmiste)*, las semillas de algodón, ricino, sésamo (ajonjolí), mostaza, cártamo, amapola (adormidera) y «karité», entre otras, se consideran semillas oleaginosas de la partida 12.07. Por el contrario, se excluyen de dicha partida los productos de las partidas 08.01 o 08.02, así como las aceitunas (Capítulos 7 o 20). 2. La partida 12.08 comprende no solo la harina sin desgrasar, sino también la desgrasada parcialmente o la que ha sido desgrasada y después total o parcialmente reengrasada con su propio aceite. Por el contrario, se excluyen los residuos de las partidas 23.04 a 23.06. 3. Las semillas de remolacha, las pratenses (de prados), las de flores ornamentales, de hortalizas, de árboles forestales o frutales, de vezas (excepto las de la especie Vicia faba) o de altramuces, se consideran semillas para siembra de la partida 12.09. Por el contrario, se excluyen de esta partida, aunque se destinen a la siembra: a) las hortalizas de vaina y el maíz dulce (Capítulo 7); b) las especias y demás productos del Capítulo 9; c) los cereales (Capítulo 10); d) los productos de las partidas 12.01 a 12.07 o de la partida 12.11. 4. La partida 12.11 comprende, entre otras, las plantas y partes de plantas de las especies siguientes: albahaca, borraja, ginseng, hisopo, regaliz, diversas especies de menta, romero, ruda, salvia y ajenjo. Por el contrario, se excluyen: a) los productos farmacéuticos del Capítulo 30; b) las preparaciones de perfumería, de tocador o de cosmética del Capítulo 33; c) los insecticidas, fungicidas, herbicidas, desinfectantes y productos similares de la partida 38.08. 5. En la partida 12.12, el término algas no comprende: a) los microorganismos monocelulares muertos de la partida 21.02; b) los cultivos de microorganismos de la partida 30.02; c) los abonos de las partidas 31.01 o 31.05. Nota de subpartida. 1. En la subpartida 1205.10, se entiende por semillas de nabo (nabina) o de colza con bajo contenido de ácido erúcico las semillas de nabo (nabina) o de colza de las que se obtiene un aceite fijo el cual tiene un contenido de ácido erúcico inferior al 2 % en peso y un componente sólido cuyo contenido de glucosinolatos es inferior a 30 micromoles por gramo. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 35', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (13, 'Capítulo', NULL, 13, 'Varios', 'Nota. 1. La partida 13.02 comprende, entre otros, los extractos de regaliz, piretro (pelitre)*, lúpulo o áloe, y el opio. Por el contrario, se excluyen: a) el extracto de regaliz con un contenido de sacarosa superior al 10 % en peso o presentado como artículo de confitería (partida 17.04); b) el extracto de malta (partida 19.01); c) los extractos de café, té o yerba mate (partida 21.01); d) los jugos y extractos vegetales que constituyan bebidas alcohólicas (Capítulo 22); e) el alcanfor natural, la glicirricina y demás productos de las partidas 29.14 o 29.38; f) los concentrados de paja de adormidera con un contenido de alcaloides superior o igual al 50 % en peso (partida 29.39); g) los medicamentos de las partidas 30.03 o 30.04 y los reactivos para determinación de los grupos o de los factores sanguíneos (partida 38.22); h) los extractos curtientes o tintóreos (partidas 32.01 o 32.03); ij) los aceites esenciales (incluidos los «concretos» o «absolutos»), los resinoides y las oleorresinas de extracción, así como los destilados acuosos aromáticos y disoluciones acuosas de aceites esenciales y las preparaciones a base de sustancias odoríferas de los tipos utilizados para la elaboración de bebidas (Capítulo 33); k) el caucho natural, balata, gutapercha, guayule, chicle y gomas naturales análogas (partida 40.01). 38 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (14, 'Capítulo', NULL, 14, 'Varios', 'Notas. 1. Se excluyen de este Capítulo y se clasifican en la Sección XI, las materias y fibras vegetales de las especies principalmente utilizadas para la fabricación de textiles, cualquiera que sea su preparación, así como las materias vegetales trabajadas especialmente para su utilización exclusiva como materia textil. 2. La partida 14.01 comprende, entre otras, el bambú (incluso hendido, aserrado longitudinalmente o cortado en longitudes determinadas, con los extremos redondeados, blanqueado, ignifugado, pulido o teñido), los trozos de mimbre, de caña y similares, la médula de roten (ratán)* y el roten (ratán)* hilado. No se clasifican en esta partida las tablillas, láminas o cintas de madera (partida 44.04). 3. La partida 14.04 no comprende la lana de madera (partida 44.05) ni las cabezas preparadas para artículos de cepillería (partida 96.03).', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (15, 'Capítulo', NULL, 15, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) el tocino y grasa de cerdo o de ave, de la partida 02.09; b) la manteca, grasa y aceite de cacao (partida 18.04); c) las preparaciones alimenticias con un contenido de productos de la partida 04.05 superior al 15 % en peso (generalmente Capítulo 21); d) los chicharrones (partida 23.01) y los residuos de las partidas 23.04 a 23.06; e) los ácidos grasos, las ceras preparadas, las grasas transformadas en productos farmacéuticos, pinturas, barnices, jabón, preparaciones de perfumería, de tocador o de cosmética, los aceites sulfonados y demás productos de la Sección VI; f) el caucho facticio derivado de los aceites (partida 40.02). 2. La partida 15.09 no incluye el aceite de aceituna extraído con disolventes (partida 15.10). 3. La partida 15.18 no comprende las grasas y aceites, ni sus fracciones, simplemente desnaturalizados, que permanecen clasificados en la partida de las correspondientes grasas y aceites, y sus fracciones, sin desnaturalizar. 4. Las pastas de neutralización, las borras o heces de aceite, la brea esteárica, la brea de suarda y la pez de glicerol, se clasifican en la partida 15.22. Notas de subpartida. 1. Para la aplicación de la subpartida 1509.30, el aceite de oliva virgen tiene una acidez libre expresada como ácido oleico inferior o igual a 2,0 g/ 100 g y puede distinguirse de las otras categorías de aceite de oliva virgen, según las características establecidas por la Norma 33-1981 del Codex Alimentarius. 2. En las subpartidas 1514.11 y 1514.19, se entiende por aceite de nabo (de nabina) o de colza con bajo contenido de ácido erúcico, el aceite fijo con un contenido de ácido erúcico inferior al 2 % en peso. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 39', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (16, 'Capítulo', NULL, 16, 'Varios', 'Notas. 1. Este Capítulo no comprende la carne, despojos, pescado, crustáceos, moluscos y demás invertebrados acuáticos, así como los insectos, preparados o conservados por los procedimientos citados en los Capítulos 2 y 3, en la Nota 6 del Capítulo 4 o en la partida 05.04 2. Las preparaciones alimenticias se clasifican en este Capítulo siempre que contengan una proporción superior al 20 % en peso de embutidos, carne, despojos, sangre, insectos, pescado o de crustáceos, moluscos o demás invertebrados acuáticos, o de una combinación de estos productos. Cuando estas preparaciones contengan dos o más productos de los mencionados, se clasifican en la partida del Capítulo 16 que corresponda al componente que predomine en peso. Estas disposiciones no se aplican a los productos rellenos de la partida 19.02 ni a las preparaciones de las partidas 21.03 o 21.04. Notas de subpartida. 1. En la subpartida 1602.10, se entiende por preparaciones homogeneizadas, las preparaciones de carne, despojos, sangre o de insectos, finamente homogeneizadas, acondicionadas para la venta al por menor como alimento para lactantes o niños de corta edad o para uso dietético en recipientes con un contenido de peso neto inferior o igual a 250 g. Para la aplicación de esta definición se hará abstracción, en su caso, de los diversos ingredientes añadidos a la preparación en pequeña cantidad para sazonar, conservar u otros fines. Estas preparaciones pueden contener pequeñas cantidades de fragmentos visibles de carne, despojos o de insectos. La subpartida 1602.10 tendrá prioridad sobre las demás subpartidas de la partida 16.02. 2. Los pescados, crustáceos, moluscos y demás invertebrados acuáticos citados en las subpartidas de las partidas 16.04 y 16.05 solo con los nombres vulgares corresponden a las mismas especies mencionadas en el Capítulo 3 con el mismo nombre. 42 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (17, 'Capítulo', NULL, 17, 'Varios', 'Nota. 1. Este Capítulo no comprende: a) los artículos de confitería que contengan cacao (partida 18.06); b) los azúcares químicamente puros (excepto la sacarosa, lactosa, maltosa, glucosa y fructosa (levulosa)) y demás productos de la partida 29.40; c) los medicamentos y demás productos del Capítulo 30. Notas de subpartida. 1. En las subpartidas 1701.12, 1701.13 y 1701.14, se entiende por azúcar en bruto, el que contenga en peso, calculado sobre producto seco, un porcentaje de sacarosa correspondiente a una lectura en el polarímetro inferior a 99,5 °. 2. La subpartida 1701.13 comprende solamente el azúcar de caña, obtenida sin centrifugación, con un contenido de sacarosa en peso, en estado seco, correspondiente a una lectura polarimétrica superior o igual a 69 º pero inferior a 93 º. El producto contiene solamente microcristales anhédricos naturales, de forma irregular, invisibles a simple vista, rodeados por residuos de melaza y demás constituyentes del azúcar de caña. 44 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (18, 'Capítulo', NULL, 18, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las preparaciones alimenticias que contengan una proporción superior al 20 % en peso de embutidos, carne, despojos, sangre, insectos, pescado o de crustáceos, moluscos o demás invertebrados acuáticos, o de una combinación de estos productos (Capítulo 16); b) las preparaciones de las partidas 04.03, 19.01, 19.02, 19.04, 19.05, 21.05, 22.02, 22.08, 30.03 o 30.04. 2. La partida 18.06 comprende los artículos de confitería que contengan cacao y, salvo lo dispuesto en la Nota 1 de este Capítulo, las demás preparaciones alimenticias que contengan cacao. Nota Complementaria. 1. En la subpartida 1801.00.00.11, la expresión «para siembra» comprende solamente los productos considerados como tales por la autoridad nacional competente. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 45', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (19, 'Capítulo', NULL, 19, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las preparaciones alimenticias que contengan una proporción superior al 20 % en peso de embutidos, carne, despojos, sangre, insectos, pescado o de crustáceos, moluscos o demás invertebrados acuáticos, o de una combinación de estos productos (Capítulo 16), excepto los productos rellenos de la partida 19.02; b) los productos a base de harina, almidón o fécula (galletas, etc.) especialmente preparados para la alimentación de los animales (partida 23.09); c) los medicamentos y demás productos del Capítulo 30. 2. En la partida 19.01, se entiende por: a) grañones, los grañones de cereales del Capítulo 11; b) harina y sémola: 1) la harina y sémola de cereales del Capítulo 11; 2) la harina, sémola y polvo, de origen vegetal, de cualquier Capítulo, excepto la harina, sémola y polvo de hortalizas secas (partida 07.12), de papa (patata)* (partida 11.05) o de hortalizas de vaina secas (partida 11.06). 3. La partida 19.04 no comprende las preparaciones con un contenido de cacao superior al 6 % en peso calculado sobre una base totalmente desgrasada, ni las recubiertas totalmente de chocolate o demás preparaciones alimenticias que contengan cacao de la partida 18.06 (partida 18.06). 4. En la partida 19.04, la expresión preparados de otro modo significa que los cereales se han sometido a un tratamiento o a una preparación más avanzados que los previstos en las partidas o en las Notas de los Capítulos 10 u 11. Nota complementaria: 1. A los efectos de la importación de pastas alimenticias clasificadas en la Partida 19.02, sólo podrán ser nacionalizadas cuando cumplan con la Norma Venezolana COVENIN de obligatorio cumplimiento N° 283:1994. A tales efectos, el Servicio Autónomo de Contraloría Sanitaria (SACS) deberá indicar en el respectivo Registro Sanitario el cumplimiento de dicha Norma para su respectivo control documental en la Oficina Aduanera de ingreso. 46 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (20, 'Capítulo', NULL, 20, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las hortalizas y frutas u otros frutos preparados o conservados por los procedimientos citados en los Capítulos 7, 8 u 11; b) las grasas y aceites, vegetales (Capítulo 15); c) las preparaciones alimenticias que contengan una proporción superior al 20 % en peso de embutidos, carne, despojos, sangre, insectos, pescado o de crustáceos, moluscos o demás invertebrados acuáticos, o de una combinación de estos productos (Capítulo 16); d) los productos de panadería, pastelería o galletería y los demás productos de la partida 19.05; e) las preparaciones alimenticias compuestas homogeneizadas de la partida 21.04. 2. Las partidas 20.07 y 20.08 no comprenden las jaleas y pastas de frutas u otros frutos, las almendras confitadas y los productos similares presentados como artículos de confitería (partida 17.04) ni los artículos de chocolate (partida 18.06). 3. Las partidas 20.01, 20.04 y 20.05 comprenden, según los casos, solo los productos del Capítulo 7 o de las partidas 11.05 u 11.06 (excepto la harina, sémola y polvo de los productos del Capítulo 8), preparados o conservados por procedimientos distintos de los mencionados en la Nota 1 a). 4. El jugo de tomate con un contenido de extracto seco superior o igual al 7 % en peso, se clasifica en la partida 20.02. 5. En la partida 20.07, la expresión obtenidos por cocción significa obtenidos por tratamiento térmico a presión atmosférica o bajo presión reducida con el fin de aumentar la viscosidad del producto por reducción de su contenido de agua u otros medios. 6. En la partida 20.09, se entiende por jugos sin fermentar y sin adición de alcohol, los jugos cuyo grado alcohólico volumétrico sea inferior o igual al 0,5 % vol. (véase la Nota 2 del Capítulo 22). Notas de subpartida. 1. En la subpartida 2005.10, se entiende por hortalizas homogeneizadas, las preparaciones de hortalizas, finamente homogeneizadas, acondicionadas para la venta al por menor como alimento para lactantes o niños de corta edad o para uso dietético en recipientes con un contenido de peso neto inferior o igual a 250 g. Para la aplicación de esta definición se hará abstracción, en su caso, de los diversos ingredientes añadidos a la preparación en pequeña cantidad para sazonar, conservar u otros fines. Estas preparaciones pueden contener pequeñas cantidades de fragmentos visibles de hortalizas. La subpartida 2005.10 tendrá prioridad sobre las demás subpartidas de la partida 20.05. 2. En la subpartida 2007.10, se entiende por preparaciones homogeneizadas, las preparaciones de frutas u otros frutos finamente homogeneizadas, acondicionadas para la venta al por menor como alimento para lactantes o niños de corta edad o para uso dietético en recipientes con un contenido de peso neto inferior o igual a 250 g. Para la aplicación de esta definición se hará abstracción, en su caso, de los diversos ingredientes añadidos a la preparación en pequeña cantidad para sazonar, conservar u otros fines. Estas preparaciones pueden contener pequeñas cantidades de fragmentos visibles de frutas u otros frutos. La subpartida 2007.10 tendrá prioridad sobre las demás subpartidas de la partida 20.07. 3. En las subpartidas 2009.12, 2009.21, 2009.31, 2009.41, 2009.61 y 2009.71, se entiende por valor Brix los grados Brix leídos directamente en la escala de un hidrómetro Brix o el índice de refracción expresado en porcentaje del contenido de sacarosa medido en refractómetro, a una temperatura de 20 º C o corregido para una temperatura de 20 º C cuando la lectura se realice a una temperatura diferente. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 47', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (21, 'Capítulo', NULL, 21, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las mezclas de hortalizas de la partida 07.12; b) los sucedáneos del café tostados que contengan café en cualquier proporción (partida 09.01); c) el té aromatizado (partida 09.02); 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 49', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (22, 'Capítulo', NULL, 22, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los productos de este Capítulo (excepto los de la partida 22.09) preparados para uso culinario de tal forma que resulten impropios para el consumo como bebida (generalmente, partida 21.03); b) el agua de mar (partida 25.01); 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 51', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (23, 'Capítulo', NULL, 23, 'Varios', 'Nota. 1. Se incluyen en la partida 23.09 los productos de los tipos utilizados para la alimentación de los animales, no expresados ni comprendidos en otra parte, obtenidos por tratamiento de materias vegetales o animales y que, por este hecho, hayan perdido las características esenciales de la materia originaria, excepto los desperdicios vegetales, residuos y subproductos vegetales procedentes de estos tratamientos. Nota de subpartida. 1. En la subpartida 2306.41, se entiende por de semillas de nabo (nabina) o de colza con bajo contenido de ácido erúcico las semillas definidas en la Nota 1 de subpartida del Capítulo 12. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 53', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (24, 'Capítulo', NULL, 24, 'Varios', 'Notas. 1. Este Capítulo no comprende los cigarrillos medicinales (Capítulo 30). 2. Cualquier producto susceptible de clasificarse en la partida 24.04 y en otra partida de este Capítulo, se clasifica en la partida 24.04. 3. En la partida 24.04, se entiende por inhalación sin combustión, la inhalación a través de calentamiento u otros medios, sin combustión. Nota de subpartida. 1. En la subpartida 2403.11, se considera tabaco para pipa de agua el tabaco destinado a ser fumado en una pipa de agua y que está constituido por una mezcla de tabaco y glicerol, incluso con aceites y extractos aromáticos, melaza o azúcar, e incluso aromatizado o saborizado con frutas. Sin embargo, los productos para pipa de agua, que no contengan tabaco, se excluyen de esta subpartida. 54 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (25, 'Capítulo', NULL, 25, 'Varios', 'Notas. 1. Salvo disposición en contrario y a reserva de lo previsto en la Nota 4 siguiente, solo se clasifican en las partidas de este Capítulo los productos en bruto o los productos lavados (incluso con sustancias químicas que eliminen las impurezas sin cambiar la estructura del producto), quebrantados, triturados, molidos, pulverizados, levigados, cribados, tamizados, enriquecidos por flotación, separación magnética u otros procedimientos mecánicos o físicos (excepto la cristalización), pero no los productos tostados, calcinados, los obtenidos por mezcla o los sometidos a un tratamiento que supere al indicado en cada partida. Se puede añadir a los productos de este Capítulo una sustancia antipolvo, siempre que no haga al producto más apto para usos determinados que para uso general. 2. Este Capítulo no comprende: a) el azufre sublimado o precipitado ni el coloidal (partida 28.02); b) las tierras colorantes con un contenido de hierro combinado, expresado en Fe2O3, superior o igual al 70 % en peso (partida 28.21); c) los medicamentos y demás productos del Capítulo 30; d) las preparaciones de perfumería, de tocador o de cosmética (Capítulo 33); e) el aglomerado de dolomita (partida 38.16); f) los adoquines, encintados (bordillos)* y losas para pavimentos (partida 68.01); los cubos, dados y artículos similares para mosaicos (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (26, 'Capítulo', NULL, 26, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las escorias y desechos industriales similares preparados en forma de macadán (partida 25.17); b) el carbonato de magnesio natural (magnesita), incluso calcinado (partida 25.19); c) los lodos procedentes de los depósitos de almacenamiento de aceites de petróleo constituidos principalmente por estos aceites (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (27, 'Capítulo', NULL, 27, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los productos orgánicos de constitución química definida presentados aisladamente; esta exclusión no afecta al metano ni al propano puros, que se clasifican en la partida 27.11; b) los medicamentos de las partidas 30.03 o 30.04; c) las mezclas de hidrocarburos no saturados, de las partidas 33.01, 33.02 o 38.05. 2. La expresión aceites de petróleo o de mineral bituminoso, empleada en el texto de la partida 27.10, se aplica, no solo a los aceites de petróleo o de mineral bituminoso, sino también a los aceites análogos, así como a los constituidos principalmente por mezclas de hidrocarburos no saturados en las que los constituyentes no aromáticos predominen en peso sobre los aromáticos, cualquiera que sea el procedimiento de obtención. Sin embargo, dicha expresión no se aplica a las poliolefinas sintéticas líquidas que destilen una proporción inferior al 60 % en volumen a 300 ° C referidos a 1.013 milibares cuando se utilice un método de destilación a baja presión (Capítulo 39). 3. En la partida 27.10, se entiende por desechos de aceites los desechos que contengan principalmente aceites de petróleo o de mineral bituminoso (tal como se definen en la Nota 2 de este Capítulo), incluso mezclados con agua. Estos desechos incluyen, principalmente: a) los aceites impropios para su utilización inicial (por ejemplo: aceites lubricantes, hidráulicos o para transformadores, usados); b) los lodos de aceites procedentes de los depósitos de almacenamiento de aceites de petróleo que contengan principalmente aceites de este tipo y una alta concentración de aditivos (por ejemplo, productos químicos) utilizados en la elaboración de productos primarios; c) los aceites que se presenten en emulsión acuosa o mezclados con agua, tales como los resultantes del derrame o lavado de depósitos de almacenamiento, o del uso de aceites de corte en las operaciones de mecanizado. Notas de subpartida. 1. En la subpartida 2701.11, se considera antracita, la hulla con un contenido límite de materias volátiles inferior o igual al 14 % , calculado sobre producto seco sin materias minerales. 2. En la subpartida 2701.12, se considera hulla bituminosa, la hulla con un contenido límite de materias volátiles superior al 14 % , calculado sobre producto seco sin materias minerales, y cuyo valor calorífico límite sea superior o igual a 5.833 kcal/ kg, calculado sobre producto húmedo sin materias minerales. 3. En las subpartidas 2707.10, 2707.20, 2707.30 y 2707.40, se consideran benzol (benceno), toluol (tolueno), xilol (xilenos) y naftaleno los productos con un contenido de benceno, tolueno, xilenos o naftaleno, superior al 50 % en peso, respectivamente. 4. En la subpartida 2710.12, se entiende por aceites livianos (ligeros)* y preparaciones, los aceites y las preparaciones que destilen, incluidas las pérdidas, una proporción superior o igual al 90 % en volumen a 210 º C, según el método ISO 3405 (equivalente al método ASTM D 86). 5. En las subpartidas de la partida 27.10, el término biodiésel designa a los ésteres monoalquílicos de ácidos grasos de los tipos utilizados como carburantes o combustibles, derivados de grasas y aceites, animales, vegetales o de origen microbiano, incluso usados. Nota Complementaria (Arancel Externo Común). 1. La expresión Gasolinas empleada en el texto de la subpartida regional 2710.12.5 comprende toda mezcla de hidrocarburos livianos apta para su utilización en motores de explosión, denominada «nafta» en Argentina, Paraguay y Uruguay. Estas mezclas no deben confundirse con las Naftas de la subpartida regional 2710.12.4 que se utilizan generalmente en petroquímica o como disolvente. Notas Complementarias. 1. En las Notas Complementarias siguientes, mientras no se indique expresamente, se aplicarán las Normas de la American Society for Testing Materials (ASTM), sobre definiciones y especificaciones normalizadas para productos petrolíferos y lubricantes. 2. Para la aplicación de la partida 27.10, se considera: a) «Aceites medios», los aceites y preparaciones que destilen en volumen, incluidas las pérdidas, menos del 90%, a 210°C, y 65% o más a 250°C (Norma ASTM D 86). b) «Aceites pesados», los aceites y preparaciones que destilen en volumen, incluidas las pérdidas, menos del 65% a 250°C (Norma ASTM D 86) o en los cuales el porcentaje de destilación a 250°C no pueda determinarse con dicha Norma. 3. Se entenderá por Espíritu de petróleo («white spirit»), un aceite liviano, sin aditivos, que destile en volumen, incluidas las pérdidas, un intervalo entre 5% y 90%, a temperatura igual o inferior a 60°C, siempre que su punto de inflamación sea superior a 21°C, según el método Abel Pensky (Norma DIN 51755) o por el método ASTM D 56. 4. Sin perjuicio de la aplicación de la Nota Complementaria 2 a), se entiende por «gasolina de aviación», aquella mezcla de hidrocarburos derivados de petróleo, gasolina natural o mezclas de hidrocarburos sintéticos o aromáticos, o ambos, libre de agua, sedimentos y de materiales sólidos en suspensión apta para ser utilizada como combustible en aviones con motores de combustión interna de encendido por chispa (motores de explosión) y que posean además las siguientes características: a) Azufre: Contenido máximo 0,05% en peso según Método D-2622 (ASTM); b) Goma: Contenido máximo, luego de 5 horas de oxidación acelerada: 6 mg/100 ml según Método D-873 (ASTM). c) Indice de antidetonante (Indice de Octano): Tipo de gasolina Método D-2700 Método D-909 80-87 80 87 100-130 100 130 115-145 115 *145 (*) Este valor se refiere al índice de operación («Perfomance Number»). d) Tensión de vapor: Máximo 0,499 Kg/cm² (49 kPa) y mínimo 0,387 Kg/cm² (38 kPa) según Método D-323 (ASTM); e) Tetraetilo de plomo: Contenido máximo según Método D-3341 (ASTM). Tipo de gasolina Tetraetilo de plomo (ml/l) 80-87 91-98 0,13 0,85 100-130 1,057 115-145 1,22 5. Se entenderá por «Queroseno», los aceites medios definidos en la Nota Complementaria 2 a) anterior, cuyo punto de inflamación sea superior a 21°C según el método «Abel-Pensky» (Norma DIN 51755) o por el método ASTM D 56. 6. Se entenderá por «gasoil» (Gasóleo), los aceites pesados definidos en la Nota Complementaria 2 b) anterior, que destilen en volumen, incluidas las pérdidas, el 85% o más a 350°C (Norma ASTM D 86). 7. Se entenderá por «Fueloils» (Fuel), el aceite pesado (distinto del gasóleo) que destilen en volumen, incluidas las pérdidas, menos del 85% a 350°C o el 25% o más, a 300°C, (Método ASTM D 86). 60 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (28, 'Capítulo', NULL, 28, 'Varios', 'Notas. 1. Salvo disposición en contrario, las partidas de este Capítulo comprenden solamente: a) los elementos químicos aislados y los compuestos de constitución química definida presentados aisladamente, aunque contengan impurezas; b) las disoluciones acuosas de los productos del apartado a) anterior; c) las demás disoluciones de los productos del apartado a) anterior, siempre que constituyan un modo de acondicionamiento usual e indispensable, exclusivamente motivado por razones de seguridad o por necesidades del transporte y que el disolvente no haga al producto más apto para usos determinados que para uso general; d) los productos de los apartados a), b) o c) anteriores, con adición de un estabilizante (incluido un antiaglomerante) indispensable para su conservación o transporte; e) los productos de los apartados a), b), c) o d) anteriores, con adición de una sustancia antipolvo o de un colorante, para facilitar su identificación o por razones de seguridad, siempre que estas adiciones no hagan al producto más apto para usos determinados que para uso general. 2. Además de los ditionitos y sulfoxilatos, estabilizados con sustancias orgánicas (partida 28.31), los carbonatos y peroxocarbonatos de bases inorgánicas (partida 28.36), los cianuros, oxicianuros y cianuros complejos de bases inorgánicas (partida 28.37), los fulminatos, cianatos y tiocianatos de bases inorgánicas (partida 28.42), los productos orgánicos comprendidos en las partidas 28.43 a 28.46 y 28.52, y los carburos (partida 28.49), solamente se clasifican en este Capítulo los compuestos de carbono que se enumeran a continuación: a) los óxidos de carbono, el cianuro de hidrógeno, los ácidos fulmínico, isociánico, tiociánico y demás ácidos cianogénicos simples o complejos (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (29, 'Capítulo', NULL, 29, 'Varios', 'Notas. 1. Salvo disposición en contrario, las partidas de este Capítulo comprenden solamente: a) los compuestos orgánicos de constitución química definida presentados aisladamente, aunque contengan impurezas; b) las mezclas de isómeros de un mismo compuesto orgánico (aunque contengan impurezas), excepto las mezclas de isómeros de los hidrocarburos acíclicos saturados o sin saturar (distintos de los estereoisómeros) (Capítulo 27); c) los productos de las partidas 29.36 a 29.39, los éteres, acetales y ésteres de azúcares, y sus sales, de la partida 29.40, y los productos de la partida 29.41, aunque no sean de constitución química definida; d) las disoluciones acuosas de los productos de los apartados a), b) o c) anteriores; e) las demás disoluciones de los productos de los apartados a), b) o c) anteriores, siempre que constituyan un modo de acondicionamiento usual e indispensable, exclusivamente motivado por razones de seguridad o necesidades del transporte y que el disolvente no haga al producto más apto para usos determinados que para uso general; f) los productos de los apartados a), b), c), d) o e) anteriores, con adición de un estabilizante (incluido un antiaglomerante) indispensable para su conservación o transporte; g) los productos de los apartados a), b), c), d), e) o f) anteriores, con adición de una sustancia antipolvo, un colorante o un odorante o un emético, para facilitar su identificación o por razones de seguridad, siempre que estas adiciones no hagan al producto más apto para usos determinados que para uso general; h) los productos siguientes, normalizados, para la producción de colorantes azoicos: sales de diazonio, copulantes utilizados para estas sales y aminas diazotables y sus sales. 2. Este Capítulo no comprende: a) los productos de la partida 15.04 y el glicerol en bruto de la partida 15.20; b) el alcohol etílico (partidas 22.07 o 22.08); c) el metano y el propano (partida 27.11); d) los compuestos de carbono mencionados en la Nota 2 del Capítulo 28; e) los productos inmunológicos de la partida 30.02; f) la urea (partidas 31.02 o 31.05); g) las materias colorantes de origen vegetal o animal (partida 32.03), las materias colorantes orgánicas sintéticas, los productos orgánicos sintéticos de los tipos utilizados como agentes de avivado fluorescente o como luminóforos (partida 32.04), así como los tintes y demás materias colorantes presentados en formas o en envases para la venta al por menor (partida 32.12); h) las enzimas (partida 35.07); ij) el metaldehído, la hexametilentetramina y los productos análogos, en tabletas, barritas o formas similares que impliquen su utilización como combustibles, así como los combustibles líquidos y los gases combustibles licuados, en recipientes de los tipos utilizados para cargar o recargar encendedores o mecheros, de capacidad inferior o igual a 300 cm3 (partida 36.06); k) los productos extintores presentados como cargas para aparatos extintores o en granadas o bombas extintoras de la partida 38.13; los productos borradores de tinta acondicionados en envases para la venta al por menor, clasificados en la partida 38.24; l) los elementos de óptica, por ejemplo, los de tartrato de etilendiamina (partida 90.01). 3. Cualquier producto que pudiera clasificarse en dos o más partidas de este Capítulo se clasificará en la última de dichas partidas por orden de numeración. 4. En las partidas 29.04 a 29.06, 29.08 a 29.11 y 29.13 a 29.20, cualquier referencia a los derivados halogenados, sulfonados, nitrados o nitrosados, se aplica también a los derivados mixtos, tales como los sulfohalogenados, nitrohalogenados, nitrosulfonados o nitrosulfohalogenados. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 75', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (30, 'Capítulo', NULL, 30, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los alimentos dietéticos, alimentos enriquecidos, alimentos para diabéticos, complementos alimenticios, bebidas tónicas y el agua mineral (Sección IV), excepto las preparaciones nutritivas para administración por vía intravenosa; b) los productos, tales como comprimidos, gomas de mascar o parches autoadhesivos (que se administran por vía transdérmica), que contengan nicotina y destinados para ayudar a dejar de fumar (partida 24.04); c) el yeso fraguable especialmente calcinado o finamente molido para uso en odontología (partida 25.20); d) los destilados acuosos aromáticos y las disoluciones acuosas de aceites esenciales, medicinales (partida 33.01); e) las preparaciones de las partidas 33.03 a 33.07, incluso si tienen propiedades terapéuticas o profilácticas; f) el jabón y demás productos de la partida 34.01, con adición de sustancias medicamentosas; g) las preparaciones a base de yeso fraguable para uso en odontología (partida 34.07); h) la albúmina de la sangre sin preparar para usos terapéuticos o profilácticos (partida 35.02); ij) los reactivos de diagnóstico de la partida 38.22. 2. En la partida 30.02 se entiende por productos inmunológicos a los péptidos y proteínas (excepto los productos de la partida 29.37) que participan directamente en la regulación de los procesos inmunológicos, tales como los anticuerpos monoclonales (MAB), los fragmentos de anticuerpos, los conjugados de anticuerpos y los conjugados de fragmentos de anticuerpos, las interleucinas, los interferones (IFN), las quimioquinas así como ciertos factores que provocan la necrosis tumoral (TNF), factores de crecimiento (GF), hematopoyetinas y factores estimulantes de colonias (CSF). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 115', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (31, 'Capítulo', NULL, 31, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) la sangre animal de la partida 05.11; b) los productos de constitución química definida presentados aisladamente, excepto los descritos en las Notas 2 a), 3 a), 4 a) o 5 siguientes; c) los cristales cultivados de cloruro de potasio (excepto los elementos de óptica), de peso unitario superior o igual a 2,5 g, de la partida 38.24; los elementos de óptica de cloruro de potasio (partida 90.01). 2. Salvo que se presenten en las formas previstas en la partida 31.05, la partida 31.02 comprende únicamente: a) los productos siguientes: 1) el nitrato de sodio, incluso puro; 2) el nitrato de amonio, incluso puro; 3) las sales dobles de sulfato de amonio y de nitrato de amonio, incluso puras; 4) el sulfato de amonio, incluso puro; 5) las sales dobles (incluso puras) o las mezclas entre sí de nitrato de calcio y nitrato de amonio; 6) las sales dobles (incluso puras) o las mezclas entre sí de nitrato de calcio y nitrato de magnesio; 7) la cianamida cálcica, incluso pura, aunque esté impregnada con aceite; 8) la urea, incluso pura; b) los abonos que consistan en mezclas entre sí de los productos del apartado a) precedente; c) los abonos que consistan en mezclas de cloruro de amonio o de productos de los apartados a) y b) precedentes, con creta, yeso natural u otras materias inorgánicas sin poder fertilizante; d) los abonos líquidos que consistan en disoluciones acuosas o amoniacales de los productos de los apartados a) 2) o a) 8) precedentes, o de una mezcla de estos productos. 132 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (32, 'Capítulo', NULL, 32, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los productos de constitución química definida presentados aisladamente, excepto los que respondan a las especificaciones de las partidas 32.03 o', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (33, 'Capítulo', NULL, 33, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las oleorresinas naturales o extractos vegetales de las partidas 13.01 o 13.02; b) el jabón y demás productos de la partida 34.01; c) las esencias de trementina, de madera de pino o de pasta celulósica al sulfato y demás productos de la partida 38.05. 2. En la partida 33.02, se entiende por sustancias odoríferas únicamente las sustancias de la partida 33.01, los ingredientes odoríferos extraídos de estas sustancias y los productos aromáticos sintéticos. 3. Las partidas 33.03 a 33.07 se aplican, entre otros, a los productos, incluso sin mezclar (excepto los destilados acuosos aromáticos y las disoluciones acuosas de aceites esenciales), aptos para ser utilizados como productos de dichas partidas y acondicionados para la venta al por menor para tales usos. 4. En la partida 33.07, se consideran preparaciones de perfumería, de tocador o de cosmética, entre otros, los siguientes productos: las bolsitas con partes de plantas aromáticas; las preparaciones odoríferas que actúan por combustión; los papeles perfumados y los papeles impregnados o recubiertos de cosméticos; las disoluciones para lentes de contacto o para ojos artificiales; la guata, fieltro y tela sin tejer, impregnados, recubiertos o revestidos de perfume o de cosméticos; las preparaciones de tocador para animales. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 137', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (34, 'Capítulo', NULL, 34, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las mezclas o preparaciones alimenticias de grasas o de aceites, animales, vegetales o de origen microbiano, de los tipos utilizados como preparaciones de desmoldeo (partida15.17); b) los compuestos aislados de constitución química definida; c) los champúes, dentífricos, cremas y espumas de afeitar y las preparaciones para el baño, que contengan jabón u otros agentes de superficie orgánicos (partidas 33.05, 33.06 o 33.07). 2. En la partida 34.01, el término jabón solo se aplica al soluble en agua. El jabón y demás productos de esta partida pueden llevar añadidas otras sustancias (por ejemplo: desinfectantes, polvos abrasivos, cargas, productos medicamentosos). Sin embargo, los que contengan abrasivos solo se clasifican en esta partida si se presentan en barras, panes, trozos o piezas troqueladas o moldeadas. Si se presentan en otras formas, se clasifican en la partida 34.05 como pastas y polvos de fregar y preparaciones similares. 3. En la partida 34.02, los agentes de superficie orgánicos son productos que, al mezclarlos con agua a una concentración del 0,5 % a 20 ° C y dejarlos en reposo durante una hora a la misma temperatura: a) producen un líquido trasparente o traslúcido o una emulsión estable sin separación de la materia insoluble; y b) reducen la tensión superficial del agua a un valor inferior o igual a 4,5 x 10-2 N/m (45 dinas/cm). 4. La expresión aceites de petróleo o de mineral bituminoso empleada en el texto de la partida 34.03 se refiere a los productos definidos en la Nota 2 del Capítulo 27. 5. Salvo las exclusiones indicadas más adelante, la expresión ceras artificiales y ceras preparadas empleada en la partida 34.04 solo se aplica: a) a los productos que presenten las características de ceras obtenidos por procedimiento químico, incluso los solubles en agua; b) a los productos obtenidos mezclando diferentes ceras entre sí; c) a los productos a base de ceras o parafinas que presenten las características de ceras y contengan, además, grasas, resinas, minerales u otras materias. Por el contrario, la partida 34.04, no comprende: a) los productos de las partidas 15.16, 34.02 o 38.23, incluso si presentan las características de ceras; b) las ceras animales sin mezclar y las ceras vegetales sin mezclar, incluso refinadas o coloreadas, de la partida 15.21; c) las ceras minerales y productos similares de la partida 27.12, incluso mezclados entre sí o simplemente coloreados; d) las ceras mezcladas, dispersas o disueltas en un medio líquido (partidas 34.05, 38.09, etc.). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 139', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (35, 'Capítulo', NULL, 35, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las levaduras (partida 21.02); b) las fracciones de la sangre (excepto la albúmina de la sangre sin preparar para usos terapéuticos o profilácticos), los medicamentos y demás productos del Capítulo 30; c) las preparaciones enzimáticas para precurtido (partida 32.02); d) las preparaciones enzimáticas para el lavado o prelavado y demás productos del Capítulo 34; e) las proteínas endurecidas (partida 39.13); f) los productos de las artes gráficas con soporte de gelatina (Capítulo 49). 2. El término dextrina empleado en la partida 35.05 se aplica a los productos de la degradación de los almidones o féculas, con un contenido de azúcares reductores, expresado en dextrosa sobre materia seca, inferior o igual al 10 % . Los productos anteriores con un contenido de azúcares reductores superior al 10 % se clasifican en la partida 17.02. 142 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (36, 'Capítulo', NULL, 36, 'Varios', 'Notas. 1. Este Capítulo no comprende los productos de constitución química definida presentados aisladamente, excepto los citados en las Notas 2 a) o 2 b) siguientes. 2. En la partida 36.06, se entiende por artículos de materias inflamables, exclusivamente: a) el metaldehído, la hexametilentetramina y productos similares, en tabletas, barritas o formas análogas, que impliquen su utilización como combustibles, así como los combustibles a base de alcohol y los combustibles preparados similares, sólidos o en pasta; b) los combustibles líquidos y los gases combustibles licuados en recipientes de los tipos utilizados para cargar o recargar encendedores o mecheros, de capacidad inferior o igual a 300 cm3; y c) las antorchas y hachos de resina, teas y similares.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (37, 'Capítulo', NULL, 37, 'Varios', 'Notas. 1. Este Capítulo no comprende los desperdicios ni los materiales de desecho. 2. En este Capítulo, el término fotográfico se refiere al procedimiento mediante el cual se forman imágenes visibles sobre superficies fotosensibles, incluidas las termosensibles, directa o indirectamente, por la acción de la luz o de otras formas de radiación. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 143', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (38, 'Capítulo', NULL, 38, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los productos de constitución química definida presentados aisladamente, excepto los siguientes: 1) el grafito artificial (partida 38.01); 2) los insecticidas, raticidas y demás antirroedores, fungicidas, herbicidas, inhibidores de germinación y reguladores del crecimiento de las plantas, desinfectantes y productos similares, presentados en las formas o envases previstos en la partida 38.08; 3) los productos extintores presentados como cargas para aparatos extintores o en granadas o bombas extintoras (partida 38.13); 4) los materiales de referencia certificados especificados en la Nota 2 siguiente; 5) los productos citados en las Notas 3 a) o 3 c) siguientes; b) las mezclas de productos químicos con sustancias alimenticias u otras que tengan valor nutritivo, de los tipos utilizados en la preparación de alimentos para consumo humano (partida 21.06, generalmente); c) los productos de la partida 24.04; d) las escorias, cenizas y residuos (incluidos los lodos, excepto los lodos de depuración), que contengan metal, arsénico o sus mezclas y cumplan las condiciones de las Notas 3 a) o 3 b) del Capítulo 26 (partida 26.20); e) los medicamentos (partidas 30.03 o 30.04); f) los catalizadores agotados de los tipos utilizados para la extracción de metal común o para la fabricación de compuestos químicos a base de metal común (partida 26.20), los catalizadores agotados de los tipos utilizados principalmente para la recuperación de metal precioso (partida 71.12), así como los catalizadores constituidos por metales o aleaciones metálicas que se presenten, por ejemplo, en forma de polvo muy fino o de tela metálica (Secciones XIV o XV). 2. A) En la partida 38.22, se entiende por material de referencia certificado el material de referencia que está acompañado por un certificado que indica los valores de las propiedades certificadas y los métodos utilizados para determinar estos valores, así como el grado de certeza asociado a cada valor, el cual es apto para ser utilizado con fines de análisis, calibración o referencia. B) Con excepción de los productos de los Capítulos 28 o 29, para la clasificación del material de referencia certificado, la partida 38.22 tiene prioridad sobre cualquier otra partida de la Nomenclatura. 3. Se clasifican en la partida 38.24 y no en otra de la Nomenclatura: a) los cristales cultivados (excepto los elementos de óptica) de óxido de magnesio o de sales halogenadas de los metales alcalinos o alcalinotérreos, de peso unitario superior o igual a 2,5 g; b) los aceites de fusel; el aceite de Dippel; c) los productos borradores de tinta acondicionados en envases para la venta al por menor; d) los productos para la corrección de clisés de mimeógrafo («stencils»), los demás correctores líquidos y las cintas correctoras (excepto las de la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (39, 'Capítulo', NULL, 39, 'Varios', 'Notas. 1. En la Nomenclatura, se entiende por plástico las materias de las partidas 39.01 a 39.14 que, sometidas a una influencia exterior (generalmente el calor y la presión y, en su caso, la acción de un disolvente o de un plastificante), son o han sido susceptibles de adquirir una forma por moldeo, colada, extrusión, laminado o cualquier otro procedimiento, en el momento de la polimerización o en una etapa posterior, forma que conservan cuando esta influencia ha dejado de ejercerse. En la Nomenclatura, el término plástico comprende también la fibra vulcanizada. Sin embargo, dicho término no se aplica a las materias textiles de la Sección XI. 2. Este Capítulo no comprende: a) las preparaciones lubricantes de las partidas 27.10 o 34.03; b) las ceras de las partidas 27.12 o 34.04; c) los compuestos orgánicos aislados de constitución química definida (Capítulo 29); d) la heparina y sus sales (partida 30.01); las disoluciones (excepto los colodiones) en disolventes orgánicos volátiles de los productos citados en los textos de las partidas 39.01 a 39.13, cuando la proporción del disolvente sea superior al 50 % del peso de la disolución (partida 32.08); las hojas para el marcado a fuego de la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (40, 'Capítulo', NULL, 40, 'Varios', 'Notas. 1. En la Nomenclatura, salvo disposición en contrario, la denominación caucho comprende los productos siguientes, incluso vulcanizados o endurecidos: caucho natural, balata, gutapercha, guayule, chicle y gomas naturales análogas, caucho sintético, caucho facticio derivado de los aceites y todos estos productos regenerados. 2. Este Capítulo no comprende: a) los productos de la Sección XI (materias textiles y sus manufacturas); b) el calzado y partes del calzado, del Capítulo 64; c) los sombreros, demás tocados, y sus partes, incluidos los gorros de baño, del Capítulo 65; d) las partes de caucho endurecido para máquinas y aparatos mecánicos o eléctricos, así como todos los objetos o partes de objetos de caucho endurecido para uso electrotécnico, de la Sección XVI; e) los artículos de los Capítulos 90, 92, 94 o 96; f) los artículos del Capítulo 95, excepto los guantes, mitones y manoplas de deporte y los artículos comprendidos en las partidas 40.11 a 40.13. 3. En las partidas 40.01 a 40.03 y 40.05, la expresión formas primarias se aplica únicamente a las formas siguientes: a) líquidos y pastas (incluido el látex, aunque esté prevulcanizado, y demás dispersiones y disoluciones); b) bloques irregulares, trozos, balas, polvo, gránulos, migas y masas no coherentes similares. 4. En la Nota 1 de este Capítulo y en la partida 40.02, la denominación caucho sintético se aplica: a) a las materias sintéticas no saturadas que puedan transformarse irreversiblemente por vulcanización con azufre en sustancias no termoplásticas que, a una temperatura comprendida entre 18 ° C y 29 ° C , puedan alargarse hasta tres veces su longitud primitiva sin romperse y que, después de alargarse hasta dos veces su longitud primitiva, adquieran en menos de cinco minutos una longitud no mayor de una vez y media su longitud primitiva. Para este ensayo, pueden añadirse las sustancias necesarias para la reticulación, tales como activadores o aceleradores de vulcanización; 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 167', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (41, 'Capítulo', NULL, 41, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los recortes y desperdicios similares de cueros y pieles en bruto (partida 05.11); b) las pieles y partes de pieles de ave, con sus plumas o plumón (partidas 05.05 o 67.01, según los casos); c) los cueros y pieles en bruto, curtidos o adobados, sin depilar, de animales de pelo (Capítulo 43). Sin embargo, se clasifican en este Capítulo las pieles en bruto sin depilar de bovino (incluidas las de búfalo), de equino, ovino (excepto las de cordero llamadas astracán, «Breitschwanz», «caracul», «persa» o similares y las pieles de cordero de Indias, de China, de Mongolia o del Tíbet), de caprino (excepto las de cabra, cabritilla o cabrito del Yemen, de Mongolia o del Tíbet), de porcino (incluidas las de pecarí), de gamuza, gacela, camello, dromedario, reno, alce, ciervo, corzo o perro. 2. A) Las partidas 41.04 a 41.06 no comprenden los cueros y pieles que hayan sufrido un proceso de curtido (incluido el precurtido) reversible (partidas', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (42, 'Capítulo', NULL, 42, 'Varios', 'Notas. 1. En este Capítulo, la expresión cuero natural comprende también los cueros y pieles agamuzados (incluido el agamuzado combinado al aceite), los cueros y pieles charolados y sus imitaciones de cueros o pieles chapados y los cueros y pieles metalizados. 2. Este Capítulo no comprende: a) los catguts estériles y las ligaduras estériles similares para suturas quirúrgicas (partida 30.06); b) las prendas y complementos (accesorios), de vestir (excepto los guantes, mitones y manoplas), de cuero o piel, forrados interiormente con peletería natural o peletería facticia o artificial, así como las prendas y complementos (accesorios), de vestir, de cuero o piel con partes exteriores de peletería natural o peletería facticia o artificial, cuando éstas superen el papel de simples guarniciones (partidas 43.03 o 43.04, según los casos); c) los artículos confeccionados con redes de la partida 56.08; d) los artículos del Capítulo 64; e) los sombreros, demás tocados, y sus partes, del Capítulo 65; f) los látigos, fustas y demás artículos de la partida 66.02; g) los gemelos, pulseras y demás artículos de bisutería (partida 71.17); h) los accesorios y guarniciones de talabartería o guarnicionería (por ejemplo: frenos, estribos, hebillas), presentados aisladamente (Sección XV, generalmente); ij) las cuerdas armónicas, parches de tambor o de instrumentos similares y demás partes de instrumentos musicales (partida 92.09); k) los artículos del Capítulo 94 (por ejemplo: muebles, luminarias y aparatos de alumbrado); l) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos); m) los botones, botones de presión, formas para botones y demás partes de botones o de botones de presión y esbozos de botones, de la partida 96.06. 3. A) Además de lo dispuesto en la Nota 2 anterior, la partida 42.02 no comprende: a) las bolsas de hojas de plástico, con asas, no concebidas para un uso prolongado, incluso impresas (partida 39.23); b) los artículos de materia trenzable (partida 46.02). B) Las manufacturas comprendidas en las partidas 42.02 y 42.03 con partes de metal precioso o de chapados de metal precioso (plaqué), de perlas finas (naturales)* o cultivadas o de piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas) permanecen incluidas en estas partidas, incluso si dichas partes exceden la función de simples accesorios o adornos de mínima importancia, a condición de que tales partes no confieran a las manufacturas su carácter esencial. Si, por el contrario, esas partes confieren a las manufacturas su carácter esencial, éstas deben clasificarse en el Capítulo 71. 4. En la partida 42.03, la expresión prendas y complementos (accesorios), de vestir se refiere, entre otros, a los guantes, mitones y manoplas (incluidos los de deporte y los de protección), a los delantales y demás equipos especiales de protección individual para cualquier oficio, a los tirantes (tiradores), cinturones, bandoleras, brazaletes y muñequeras, excepto las pulseras para relojes (partida 91.13). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 175', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (43, 'Capítulo', NULL, 43, 'Varios', 'Notas. 1. Independientemente de la peletería en bruto de la partida 43.01, en la Nomenclatura, el término peletería abarca las pieles de todos los animales curtidas o adobadas, sin depilar. 2. Este Capítulo no comprende: a) las pieles y partes de pieles de ave con sus plumas o plumón (partidas 05.05 o 67.01, según los casos); b) los cueros y pieles, en bruto, sin depilar, de la naturaleza de los clasificados en el Capítulo 41 en virtud de la Nota 1 c) de dicho Capítulo; c) los guantes, mitones y manoplas, confeccionados a la vez con peletería natural o peletería facticia o artificial y con cuero (partida 42.03); d) los artículos del Capítulo 64; e) los sombreros, demás tocados, y sus partes, del Capítulo 65; f) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos). 3. Se clasifican en la partida 43.03, la peletería y partes de peletería, ensambladas con otras materias, y la peletería y partes de peletería, cosidas formando prendas, partes de prendas, complementos (accesorios), de vestir u otros artículos. 4. Se clasifican en las partidas 43.03 o 43.04, según los casos, las prendas y complementos (accesorios), de vestir, de cualquier clase (excepto los excluidos de este Capítulo por la Nota 2), forrados interiormente con peletería natural o con peletería facticia o artificial, así como las prendas y complementos (accesorios), de vestir, con partes exteriores de peletería natural o peletería facticia o artificial, cuando dichas partes no sean simples guarniciones. 5. En la Nomenclatura, se consideran peletería facticia o artificial las imitaciones de peletería obtenidas con lana, pelo u otras fibras, aplicados por pegado o cosido, sobre cuero, tejido u otras materias, excepto las imitaciones obtenidas por tejido o por punto (partidas 58.01 o 60.01, generalmente). 176 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (44, 'Capítulo', NULL, 44, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las virutas y astillas de madera ni la madera triturada, molida o pulverizada, de las especies utilizadas principalmente en perfumería, en medicina o para usos insecticidas, parasiticidas o similares (partida 12.11); b) el bambú ni demás materias de naturaleza leñosa de las especies utilizadas principalmente en cestería o espartería, en bruto, incluso hendidos, aserrados longitudinalmente o cortados en longitudes determinadas (partida 14.01); c) las virutas y astillas de madera ni la madera molida o pulverizada, de las especies utilizadas principalmente como tintóreas o curtientes (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (45, 'Capítulo', NULL, 45, 'Varios', 'Nota. 1. Este Capítulo no comprende: a) el calzado y sus partes, del Capítulo 64; b) los sombreros, demás tocados, y sus partes, del Capítulo 65; c) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos). d) los vehículos y las cajas para vehículos, de cestería (Capítulo 87); e) los artículos del Capítulo 94 (por ejemplo: muebles, luminarias y aparatos de alumbrado). 3. En la partida 46.01, se consideran materia trenzable, trenzas y artículos similares de materia trenzable, paralelizados, los artículos constituidos por materia trenzable, trenzas o artículos similares de materia trenzable, yuxtapuestos formando napas por medio de ligaduras, aunque estas últimas sean de materia textil hilada.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (46, 'Capítulo', NULL, 46, 'Varios', 'Notas. 1. En este Capítulo, la expresión materia trenzable se refiere a materias en un estado o forma tales que puedan trenzarse, entrelazarse o trabajarse de modo análogo. Se consideran como tales, por ejemplo: la paja, mimbre, sauce, bambú, roten (ratán)*, junco, caña, cintas de madera, tiras de otros vegetales (por ejemplo: tiras de corteza, hojas estrechas y rafia u otras tiras obtenidas de hojas anchas), fibras textiles naturales sin hilar, monofilamentos, tiras y formas similares de plástico y tiras de papel, pero no las tiras de cuero o piel preparados o de cuero regenerado, de fieltro o tela sin tejer, ni el cabello, crin, mechas e hilados de materia textil ni monofilamentos, tiras y formas similares del Capítulo 54. 2. Este Capítulo no comprende: a) los revestimientos de paredes de la partida 48.14; b) los cordeles, cuerdas y cordajes, trenzados o no (partida 56.07); c) el calzado y los sombreros, demás tocados, y sus partes, de los Capítulos 64 y 65; 182 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (47, 'Capítulo', NULL, 47, 'Varios', 'Nota. 1. En la partida 47.02, se entiende por pasta química de madera para disolver la pasta química cuya fracción de pasta insoluble después de una hora en una disolución al 18 % de hidróxido de sodio (NaOH) a 20 ° C , sea superior o igual al 92 % en peso en la pasta de madera a la sosa (soda) o al sulfato o superior o igual al 88 % en peso en la pasta de madera al sulfito, siempre que en este último caso el contenido de cenizas sea inferior o igual al 0,15 % en peso.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (48, 'Capítulo', NULL, 48, 'Varios', 'Notas. 1. En este Capítulo, salvo disposición en contrario, toda referencia a papel incluye también al cartón, sin que se tenga en cuenta el espesor o el peso por m2. 2. Este Capítulo no comprende: a) los artículos del Capítulo 30; b) las hojas para el marcado a fuego de la partida 32.12; c) los papeles perfumados y los papeles impregnados o recubiertos de cosméticos (Capítulo 33); d) el papel y la guata de celulosa impregnados, recubiertos o revestidos de jabón o de detergentes (partida 34.01), o de cremas, encáusticos, abrillantadores (lustres) o preparaciones similares (partida 34.05); e) el papel y cartón sensibilizados de las partidas 37.01 a 37.04; f) el papel impregnado con reactivos de diagnóstico o de laboratorio (partida 38.22); 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 183 g) el plástico estratificado con papel o cartón, los productos constituidos por una capa de papel o cartón recubiertos o revestidos de una capa de plástico cuando el espesor de esta última sea superior a la mitad del espesor total, y las manufacturas de estas materias, excepto los revestimientos para paredes de la partida 48.14 (Capítulo 39); h) los artículos de la partida 42.02 (por ejemplo, artículos de viaje); ij) los artículos del Capítulo 46 (manufacturas de espartería o cestería); k) los hilados de papel y los artículos textiles de hilados de papel (Sección XI); l) los artículos de los Capítulos 64 o 65; m) los abrasivos aplicados sobre papel o cartón (partida 68.05) y la mica aplicada sobre papel o cartón (partida 68.14); por el contrario, el papel o cartón revestidos de polvo de mica se clasifican en este Capítulo; n) las hojas y tiras delgadas de metal con soporte de papel o cartón (generalmente Secciones XIV o XV); o) los artículos de la partida 92.09; p) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos); q) los artículos del Capítulo 96 (por ejemplo: botones, compresas y tampones higiénicos, pañales). 3. Salvo lo dispuesto en la Nota 7, se clasifican en las partidas 48.01 a 48.05 el papel y cartón que, por calandrado u otro modo, se hayan alisado, satinado, abrillantado, glaseado, pulido o sometido a otras operaciones de acabado similares, o a un falso afiligranado o un aprestado en la superficie, así como el papel, cartón, guata de celulosa y napa de fibras de celulosa, coloreados o jaspeados en la masa por cualquier procedimiento. Salvo lo dispuesto en la partida 48.03, estas partidas no se aplican al papel, cartón, guata de celulosa y napa de fibras de celulosa que hayan sido tratados de otro modo. 4. En este Capítulo, se considera papel prensa el papel sin estucar ni recubrir del tipo utilizado para la impresión de diarios, en el que el contenido de fibras de madera obtenidas por procedimiento mecánico o químico-mecánico sea superior o igual al 50 % en peso del contenido total de fibra, sin encolar o muy ligeramente encolado, cuyo índice de rugosidad, medido en el aparato Parker Print Surf (1 MPa) sobre cada una de las caras, sea superior a 2,5 micrómetros (micras, micrones)* y de peso superior o igual a 40 g/m² pero inferior o igual a 65 g/m² y presentado exclusivamente a) en tiras o bobinas (rollos) de anchura superior a 28 cm; o b) en hojas de forma cuadrada o rectangular en las que sus lados sean superiores a 28 cm y a 15 cm, medidos sin plegar. 5. En la partida 48.02, se entiende por papel y cartón de los tipos utilizados para escribir, imprimir u otros fines gráficos y papel y cartón para tarjetas o cintas para perforar (sin perforar), el papel y cartón fabricados principalmente con pasta blanqueada o con pasta obtenida por procedimiento mecánico o químico-mecánico que cumplan alguna de las condiciones siguientes: A) Para el papel o cartón de peso inferior o igual a 150 g/m2: a) un contenido de fibras obtenidas por procedimiento mecánico o químico-mecánico superior o igual al 10 % , y 1) un peso inferior o igual a 80 g/m2, o 2) estar coloreado en la masa; b) un contenido de cenizas superior al 8 %, y 1) un peso inferior o igual a 80 g/m2, o 2) estar coloreado en la masa; c) un contenido de cenizas superior al 3 % y un grado de blancura (factor de reflectancia) superior o igual al 60 % ; d) un contenido de cenizas superior al 3 % pero inferior o igual al 8 % , un grado de blancura (factor de reflectancia) inferior al 60 % y un índice de resistencia al estallido inferior o igual a 2,5 kPam2/g; e) un contenido de cenizas inferior o igual al 3 % , un grado de blancura (factor de reflectancia) superior o igual al 60 % y un índice de resistencia al estallido inferior o igual a 2,5 kPam2/g; B) Para el papel o cartón de peso superior a 150 g/m2: a) estar coloreado en la masa; b) un grado de blancura (factor de reflectancia) superior o igual al 60 % , y 1) un espesor inferior o igual a 225 micrómetros (micras, micrones)*, o 2) un espesor superior a 225 micras micrómetros (micras, micrones)* pero inferior o igual a 508 micrómetros (micras, micrones)* y un contenido de cenizas superior al 3 % ; Peso Resistencia mínima al estallido Mullen g/m² _______ kPa ___________________________________ 115 393 125 417 200 637 300 824 400 961 2. En las subpartidas 4804.21 y 4804.29, se considera papel Kraft para sacos (bolsas) el papel alisado en ambas caras, presentado en bobinas (rollos), en el que el contenido de fibras obtenidas por el procedimiento químico al sulfato o a la sosa (soda) sea superior o igual al 80 % en peso del contenido total de fibra, de peso superior o igual a 60 g/m² pero inferior o igual a 115 g/m², y que responda a una de las condiciones siguientes: a) que tenga un índice de estallido Mullen superior o igual a 3,7 kPam2/g y un alargamiento superior al 4,5 % en la dirección transversal y al 2 % en la dirección longitudinal de la máquina; b) que tenga la resistencia mínima al desgarre y a la ruptura por tracción indicadas en el cuadro siguiente o sus equivalentes interpolados linealmente para cualquier otro peso: Peso Resistencia mínima al desgarre mN Resistencia mínima a la ruptura por tracción kN/m g/m2 Dirección longitudinal de la máquina Dirección longitudinal de la máquina más dirección transversal Dirección transversal Dirección longitudinal de la máquina más dirección transversal 60 700 1.510 1,9 6,0 70 830 1.790 2,3 7,2 80 965 2.070 2,8 8,3 100 1.230 2.635 3,7 10,6 115 1.425 3.060 4,4 12,3 c) un grado de blancura (factor de reflectancia) inferior al 60 % , un espesor inferior o igual a 254 micrómetros (micras, micrones)* y un contenido de cenizas superior al 8 % . Sin embargo, la partida 48.02 no comprende el papel y cartón filtro (incluido el papel para bolsitas de té) ni el papel y cartón fieltro. 6. En este Capítulo, se entiende por papel y cartón Kraft, el papel y cartón con un contenido de fibras obtenidas por procedimiento químico al sulfato o a la sosa (soda) superior o igual al 80 % en peso del contenido total de fibra. 7. Salvo disposición en contrario en los textos de partida, el papel, cartón, guata de celulosa y napa de fibras de celulosa, que puedan clasificarse en dos o más de las partidas 48.01 a 48.11, se clasifican en la que, de entre ellas, figure en la Nomenclatura en último lugar por orden de numeración. 8. En las partidas 48.03 a 48.09, se clasifican solamente el papel, cartón, guata de celulosa y napa de fibras de celulosa que se presenten en una de las formas siguientes: a) tiras o bobinas (rollos) de anchura superior a 36 cm; o b) hojas en forma cuadrada o rectangular en las que sus lados sean superiores a 36 cm y a 15 cm, medidos sin plegar. 9. En la partida 48.14, se entiende por papel para decorar y revestimientos similares de paredes o techos: a) el papel en bobinas (rollos) de anchura superior o igual a 45 cm pero inferior o igual a 160 cm, adecuado para la decoración de paredes o de techos: 1) graneado, gofrado, coloreado, impreso con motivos o decorado de otro modo en la superficie (por ejemplo, con tundizno), incluso recubierto o revestido de un plástico protector transparente; o 2) con la superficie graneada debido a la presencia de partículas de madera, de paja, etc; o 3) recubierto o revestido en la cara vista con plástico que esté graneado, gofrado, coloreado, impreso con motivos o decorado de otro modo; o 4) revestido en la cara vista con materia trenzable, incluso tejida en forma plana o paralelizada; b) las cenefas y frisos de papel, tratados como los anteriores, incluso en bobinas (rollos), adecuados para la decoración de paredes o techos; c) los revestimientos murales de papel constituidos por varios paneles, en bobinas (rollos) o en hojas, impresos de modo que formen un paisaje, una figura u otro motivo después de colocados en la pared. Las manufacturas con soporte de papel o cartón susceptibles de utilizarse como cubresuelos o como revestimientos de paredes se clasifican en la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (49, 'Capítulo', NULL, 49, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los negativos y positivos fotográficos con soporte transparente (Capítulo 37); b) los mapas, planos y esferas, en relieve, incluso impresos (partida 90.23); c) los naipes y demás artículos del Capítulo 95; d) los grabados, estampas y litografías originales (partida 97.02), los sellos (estampillas) de correo, timbres fiscales, marcas postales, sobres primer día, enteros postales, demás artículos franqueados y análogos de la partida 97.04, las antigüedades de más de cien años y demás artículos del Capítulo 97. 2. En el Capítulo 49, el término impreso significa también reproducido con copiadora, obtenido por un procedimiento controlado por una máquina automática para tratamiento o procesamiento de datos, por estampado en relieve, fotografía, fotocopia, termocopia o mecanografiado. 3. Los diarios y publicaciones periódicas encuadernados, así como las colecciones de diarios o de publicaciones periódicas presentadas bajo una misma cubierta, se clasifican en la partida 49.01, aunque contengan publicidad. 4. También se clasifican en la partida 49.01: a) las colecciones de grabados, de reproducciones de obras de arte, de dibujos, etc., que constituyan obras completas, paginadas y susceptibles de formar un libro, cuando los grabados estén acompañados de un texto referido a las obras o a sus autores; b) las láminas ilustradas que se presenten al mismo tiempo que un libro y como complemento de éste; c) los libros presentados en fascículos o en hojas separadas, de cualquier formato, que constituyan una obra completa o parte de una obra para encuadernar en rústica o de otra forma. Sin embargo, los grabados e ilustraciones, que no tengan texto y se presenten en hojas separadas de cualquier formato, se clasifican en la partida 49.11. 5. Salvo lo dispuesto en la Nota 3 de este Capítulo, la partida 49.01 no comprende las publicaciones consagradas fundamentalmente a la publicidad (por ejemplo: folletos, prospectos, catálogos comerciales, anuarios publicados por asociaciones comerciales, propaganda turística). Estas publicaciones se clasifican en la partida 49.11. 6. En la partida 49.03, se consideran álbumes o libros de estampas para niños los álbumes o libros para niños cuyas ilustraciones sean el atractivo principal y cuyos textos solo tengan un interés secundario. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 193', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (51, 'Capítulo', NULL, 51, 'Varios', 'Nota. 1. En la Nomenclatura se entiende por: a) lana, la fibra natural que recubre los ovinos; b) pelo fino, el pelo de alpaca, llama (incluido el guanaco), vicuña, camello, dromedario, yac, cabra de Angora («mohair»), cabra del Tíbet, cabra de Cachemira o cabras similares (excepto cabras comunes), conejo (incluido el conejo de Angora), liebre, castor, coipo o rata almizclera; c) pelo ordinario, el pelo de los animales no citados anteriormente, excepto el pelo y las cerdas de cepillería (partida 05.02) y la crin (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (52, 'Capítulo', NULL, 52, 'Varios', 'Nota de subpartida. 1. En las subpartidas 5209.42 y 5211.42, se entiende por tejidos de mezclilla («denim») los tejidos con hilados de distintos colores, de ligamento sarga de curso inferior o igual a 4, incluida la sarga quebrada (a veces llamada raso de 4), de efecto por urdimbre, en los que los hilos de urdimbre sean de un solo y mismo color y los de trama, crudos, blanqueados, teñidos de gris o coloreados con un matiz más claro que el utilizado en los hilos de urdimbre. 198 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (54, 'Capítulo', NULL, 54, 'Varios', 'Notas. 1. En la Nomenclatura, las expresiones fibras sintéticas y fibras artificiales se refieren a las fibras discontinuas y a los filamentos de polímeros orgánicos obtenidos industrialmente: a) por polimerización de monómeros orgánicos para obtener polímeros tales como poliamidas, poliésteres, poliolefinas o poliuretanos, o por modificación química de polímeros obtenidos por este procedimiento (por ejemplo, poli(alcohol vinílico) obtenido por hidrólisis del poli(acetato de vinilo)); b) por disolución o tratamiento químico de polímeros orgánicos naturales (por ejemplo, celulosa) para obtener polímeros tales como rayón cuproamónico (cupro) o rayón viscosa, o por modificación química de polímeros orgánicos naturales (por ejemplo: celulosa, caseína y otras proteínas, o ácido algínico) para obtener polímeros tales como acetato de celulosa o alginatos. Se consideran sintéticas las fibras definidas en a) y artificiales las definidas en b). Las tiras y formas similares de la partida 54.04 o 54.05 no se consideran fibras sintéticas o artificiales. Los términos sintético y artificial se aplican también, con el mismo sentido, a la expresión materia textil. 2. Las partidas 54.02 y 54.03 no comprenden los cables de filamentos sintéticos o artificiales del Capítulo 55. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 203', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (55, 'Capítulo', NULL, 55, 'Varios', 'Nota. 1. En las partidas 55.01 y 55.02, se entiende por cables de filamentos sintéticos y cables de filamentos artificiales, los cables constituidos por un conjunto de filamentos paralelos de longitud uniforme e igual a la de los cables, que satisfagan las condiciones siguientes: a) longitud del cable superior a 2 m; b) torsión del cable inferior a 5 vueltas por metro; c) título unitario de los filamentos inferior a 67 decitex; d) solamente para los cables de filamentos sintéticos: que hayan sido estirados y, por ello, no puedan alargarse una proporción superior al 100 % de su longitud; e) título total del cable superior a 20.000 decitex. Los cables de longitud inferior o igual a 2 m se clasifican en las partidas 55.03 o 55.04. 206 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (56, 'Capítulo', NULL, 56, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) la guata, fieltro y tela sin tejer, impregnados, recubiertos o revestidos de sustancias o preparaciones (por ejemplo: de perfume o cosméticos del Capítulo 33, de jabón o detergentes de la partida 34.01, de betunes o cremas para el calzado, encáusticos, abrillantadores (lustres), etc. o preparaciones similares de la partida 34.05, de suavizantes para textiles de la partida 38.09), cuando la materia textil sea un simple soporte; b) los productos textiles de la partida 58.11; c) los abrasivos naturales o artificiales, en polvo o gránulos, con soporte de fieltro o tela sin tejer (partida 68.05); d) la mica aglomerada o reconstituida con soporte de fieltro o tela sin tejer (partida 68.14); e) las hojas y tiras delgadas de metal con soporte de fieltro o tela sin tejer (generalmente Secciones XIV o XV); f) las compresas y los tampones higiénicos, pañales y artículos similares de la partida 96.19. 2. El término fieltro comprende también el fieltro punzonado y los productos constituidos por una capa de fibra textil cuya cohesión se ha reforzado mediante costura por cadeneta con las fibras de la propia capa. 3. Las partidas 56.02 y 56.03 comprenden respectivamente el fieltro y la tela sin tejer, impregnados, recubiertos, revestidos o estratificados con plástico o caucho, cualquiera que sea la naturaleza de estas materias (compacta o celular). La partida 56.03 comprende, además, la tela sin tejer aglomerada con plástico o caucho. Las partidas 56.02 y 56.03 no comprenden, sin embargo: a) el fieltro impregnado, recubierto, revestido o estratificado, con plástico o caucho, con un contenido de materia textil inferior o igual al 50 % en peso, así como el fieltro inmerso totalmente en plástico o caucho (Capítulos 39 o 40); b) la tela sin tejer totalmente inmersa en plástico o caucho o totalmente recubierta o revestida por las dos caras con estas mismas materias, siempre que el recubrimiento o revestimiento sea perceptible a simple vista, hecha abstracción para la aplicación de esta disposición de los cambios de color producidos por estas operaciones (Capítulos 39 o 40); c) las placas, hojas o tiras, de plástico o caucho celulares, combinadas con fieltro o tela sin tejer, en las que la materia textil sea un simple soporte (Capítulos 39 o 40). 4. La partida 56.04 no comprende los hilados textiles, ni las tiras y formas similares de las partidas 54.04 o 54.05, cuya impregnación, recubrimiento o revestimiento no sea perceptible a simple vista (Capítulos 50 a 55, generalmente); para la aplicación de esta disposición, se hará abstracción de los cambios de color producidos por estas operaciones. 210 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (57, 'Capítulo', NULL, 57, 'Varios', 'Notas. 1. En este Capítulo, se entiende por alfombras y demás revestimientos para el suelo, de materia textil, cualquier revestimiento para el suelo cuya superficie de materia textil quede al exterior después de colocado. También están comprendidos los artículos que tengan las características de los revestimientos para el suelo de materia textil pero que se utilicen para otros fines. 2. Este Capítulo no comprende los productos textiles planos y bastos de protección que se colocan bajo las alfombras y demás revestimientos para el suelo. 212 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (58, 'Capítulo', NULL, 58, 'Varios', 'Notas. 1. No se clasifican en este Capítulo los tejidos especificados en la Nota 1 del Capítulo 59, impregnados, recubiertos, revestidos o estratificados ni los demás productos del Capítulo 59. 2. Se clasifican también en la partida 58.01 el terciopelo y la felpa por trama sin cortar todavía que no presenten ni pelo ni bucles en la superficie. 3. En la partida 58.03, se entiende por tejido de gasa de vuelta el tejido en el que la urdimbre esté compuesta en toda o parte de su superficie por hilos fijos (hilos derechos) y por hilos móviles (hilos de vuelta) que se cruzan con los fijos dando media vuelta, una vuelta completa o más de una vuelta, para formar un bucle que aprisiona la trama. 4. No se clasifican en la partida 58.04 las redes de mallas anudadas, en paño o en pieza, fabricadas con cordeles, cuerdas o cordajes, de la partida 56.08. 5. En la partida 58.06, se entiende por cintas: a) - los tejidos (incluido el terciopelo) en tiras de anchura inferior o igual a 30 cm y con orillos verdaderos; - las tiras de anchura inferior o igual a 30 cm obtenidas por corte de tejido y provistas de falsos orillos tejidos, pegados u obtenidos de otra forma; b) los tejidos tubulares que, aplanados, tengan una anchura inferior o igual a 30 cm; c) los tejidos al bies con bordes plegados de anchura inferior o igual a 30 cm una vez desplegados. Las cintas con flecos obtenidos durante el tejido se clasifican en la partida 58.08. 6. El término bordados de la partida 58.10 se extiende a las aplicaciones por costura de lentejuelas, cuentas o motivos decorativos de textil u otra materia, así como a los trabajos realizados con hilos bordadores de metal o fibra de vidrio. Se excluye de la partida 58.10 la tapicería de aguja (partida 58.05). 7. Además de los productos de la partida 58.09, se clasifican también en las partidas de este Capítulo los productos hechos con hilos de metal, de los tipos utilizados en prendas de vestir, tapicería o usos similares. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 213', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (59, 'Capítulo', NULL, 59, 'Varios', 'Notas. 1. Salvo disposición en contrario, cuando se utilice en este Capítulo el término tela(s), se refiere a los tejidos de los Capítulos 50 a 55 y de las partidas 58.03 y 58.06, a las trenzas, artículos de pasamanería y artículos ornamentales análogos, en pieza, de la partida 58.08 y a los tejidos de punto de las partidas', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (60, 'Capítulo', NULL, 60, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los encajes de croché o ganchillo de la partida 58.04; b) las etiquetas, escudos y artículos similares, de punto, de la partida 58.07; c) los tejidos de punto impregnados, recubiertos, revestidos o estratificados, del Capítulo 59. Sin embargo, el terciopelo, la felpa y los tejidos con bucles, de punto, incluso impregnados, recubiertos, revestidos o estratificados, se clasifican en la partida 60.01. 2. Este Capítulo comprende también los tejidos de punto fabricados con hilos de metal, de los tipos utilizados en prendas de vestir, tapicería o usos similares. 3. En la Nomenclatura, la expresión de punto incluye los productos obtenidos mediante costura por cadeneta en los que las mallas estén constituidas por hilados textiles. Nota de subpartida. 1. La subpartida 6005.35 comprende los tejidos de monofilamentos de polietileno o de multifilamentos de poliéster, con un peso superior o igual a 30 g/m2 pero inferior o igual a 55 g/m2, cuya malla contenga una cantidad superior o igual a 20 perforaciones/cm2 pero inferior o igual a 100 perforaciones/cm2, impregnados o recubiertos con alfa-cipermetrina (ISO), clorfenapir (ISO), deltametrina (DCI, ISO), lambda-cialotrina (ISO), permetrina (ISO) o pirimifos- metil (ISO). 216 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (61, 'Capítulo', NULL, 61, 'Varios', 'Notas. 1. Este Capítulo solo comprende artículos de punto confeccionados. 2. Este Capítulo no comprende: a) los artículos de la partida 62.12; b) los artículos de prendería de la partida 63.09; c) los artículos de ortopedia, tales como bragueros para hernias, fajas medicoquirúrgicas (partida 90.21). 3. En las partidas 61.03 y 61.04: a) se entiende por trajes (ambos o ternos) y trajes sastre los surtidos formados por dos o tres prendas de vestir confeccionadas en su superficie exterior con la misma tela y compuestos por: - una sola chaqueta (saco) que cubra la parte superior del cuerpo, cuyo exterior, excepto las mangas, esté constituido por cuatro o más piezas, eventualmente acompañada de un solo chaleco sastre en el que su parte delantera esté confeccionada con la misma tela que la superficie exterior de los demás componentes del surtido y cuya espalda sea de la misma tela que el forro de la chaqueta (saco); y - una sola prenda que cubra la parte inferior del cuerpo y que consista en un pantalón largo, un pantalón corto (calzón), un short (excepto de baño), una falda o una falda pantalón, sin tirantes (tiradores) ni peto. Todos los componentes del traje (ambo o terno) o del traje sastre deberán confeccionarse con una tela de la misma estructura, color y composición; además, deberán ser del mismo estilo y de tallas correspondientes o compatibles. Sin embargo, estos componentes pueden presentar un vivo (tira de tela cosida a las costuras) de una tela diferente. Si se presentan simultáneamente varias prendas de la parte inferior, por ejemplo: un pantalón largo y un short o dos pantalones largos, o una falda o falda pantalón y un pantalón, se dará prioridad al pantalón largo o a uno de ellos como parte inferior constitutiva del traje (ambo o terno), y a la falda o falda pantalón en el caso del traje sastre, clasificándose separadamente las demás prendas. Aunque no cumplan todas las condiciones antes citadas, la expresión trajes (ambos o ternos) también comprende los trajes de etiqueta o de noche siguientes: - el chaqué, en el que la chaqueta (saco), lisa, presenta faldones redondeados que descienden muy bajo hacia atrás, con un pantalón de rayas verticales; - el frac, hecho generalmente de tela negra, con una chaqueta (saco) relativamente corta por delante, que se mantiene abierta, con los faldones estrechos, escotados en las caderas y colgantes por detrás; - el esmoquin, en el que la chaqueta (saco), aunque quizás permita mayor visibilidad de la pechera, es de corte similar al de la chaqueta (saco) común y presenta la particularidad de llevar solapas brillantes de seda o de imitación de seda. b) Se entiende por conjunto un surtido de prendas de vestir (excepto los artículos de las partidas 61.07, 61.08 o 61.09) que comprenda varias prendas confeccionadas con una misma tela, acondicionado para la venta al por menor y compuesto por: - una sola prenda que cubra la parte superior del cuerpo, excepto el pulóver que puede constituir una segunda prenda exterior solamente en el caso de los «twinset» o un chaleco que puede constituir una segunda prenda en los demás casos; y - una o dos prendas diferentes que cubran la parte inferior del cuerpo y que consistan en un pantalón largo, un pantalón con peto, un pantalón corto (calzón), un short (excepto de baño), una falda o una falda pantalón. Todos los componentes del conjunto deben tener la misma estructura, estilo, color y composición; además, deben ser de tallas correspondientes o compatibles. El término conjunto no comprende los conjuntos de abrigo para entrenamiento o deporte ni los monos (overoles) y conjuntos de esquí, de la partida 61.12. 4. Las partidas 61.05 y 61.06 no comprenden las prendas de vestir con bolsillos por debajo de la cintura o con acanalado elástico u otro medio para ceñir el bajo de la prenda, ni las prendas que tengan una media inferior a 10 puntos por centímetro lineal en cada dirección, contados en una superficie mínima de 10 cm x 10 cm. La partida 61.05 no comprende las prendas sin mangas. Las camisas y blusas camiseras son prendas destinadas a cubrir la parte superior del cuerpo y llevan mangas, largas o cortas, así como una abertura, incluso parcial, a partir del escote. Las blusas son prendas holgadas también destinadas a cubrir la parte superior del cuerpo. Pueden carecer de mangas y tener o no una abertura en el escote. Las camisas, blusas y blusas camiseras también pueden tener un cuello. 5. La partida 61.09 no comprende las prendas de vestir con acanalado elástico, cordón corredizo u otro medio para ceñir el bajo. 6. En la partida 61.11: a) la expresión prendas y complementos (accesorios), de vestir, para bebés se refiere a los artículos para niños de corta edad con estatura no superior a 86 cm; b) los artículos susceptibles de clasificarse en la partida 61.11 y en otras partidas de este Capítulo se clasifican en la partida 61.11. 7. En la partida 61.12, se entiende por monos (overoles) y conjuntos de esquí, las prendas de vestir o surtidos de prendas de vestir que, por su aspecto general y su textura, sean identificables como destinados principalmente para uso en la práctica del esquí (alpino o de fondo). Se componen de: a) un mono (overol) de esquí, es decir, una prenda de una sola pieza que cubre la parte superior y la inferior del cuerpo; además de mangas y cuello, este artículo puede llevar bolsillos y trabillas; o b) un conjunto de esquí, es decir, un surtido de prendas de vestir que comprenda dos o tres prendas, acondicionado para la venta al por menor y compuesto por: - una sola prenda del tipo anorak, cazadora o artículo similar, con cierre de cremallera (cierre relámpago), eventualmente acompañada de un chaleco; y - un solo pantalón, aunque suba por encima de la cintura, un solo pantalón corto (calzón) o un solo pantalón con peto. El conjunto de esquí puede también estar compuesto por un mono (overol) de esquí del tipo mencionado anteriormente y por una especie de chaqueta (saco) acolchada sin mangas que se viste sobre el mono (overol). Todos los componentes del conjunto de esquí deben estar confeccionados con una tela de la misma textura, estilo y composición, del mismo color o de colores distintos; además, deben ser de tallas correspondientes o compatibles. 8. Las prendas de vestir susceptibles de clasificarse en la partida 61.13 y en otras partidas de este Capítulo, excepto en la partida 61.11, se clasifican en la partida 61.13. 9. Las prendas de vestir de este Capítulo que se cierren por delante de izquierda sobre derecha se consideran como prendas para hombres o niños, y aquellas que se cierren por delante de derecha sobre izquierda, como prendas para mujeres o niñas. Estas disposiciones no se aplicarán cuando el corte de la prenda indique manifiestamente que ha sido diseñada para uno u otro sexo. Las prendas que no sean identificables como prendas para hombres o niños, o como prendas para mujeres o niñas, se clasifican con estas últimas. 10. Los artículos de este Capítulo pueden confeccionarse con hilos de metal. 218 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (62, 'Capítulo', NULL, 62, 'Varios', 'Notas. 1. Este Capítulo solo se aplica a los artículos confeccionados con cualquier textil, excepto la guata y los artículos de punto distintos de los de la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (63, 'Capítulo', NULL, 63, 'Varios', 'Notas. 1. El Subcapítulo I, que comprende artículos de cualquier textil, solo se aplica a los artículos confeccionados. 2. El Subcapítulo I no comprende: a) los productos de los Capítulos 56 a 62; b) los artículos de prendería de la partida 63.09. 3. La partida 63.09 solo comprende los artículos citados limitativamente a continuación: a) artículos de materias textiles: - prendas y complementos (accesorios), de vestir, y sus partes; - mantas; - ropa de cama, mesa, tocador o cocina; - artículos de tapicería, excepto las alfombras de las partidas 57.01 a 57.05 y la tapicería de la partida 58.05; b) calzado, sombreros y demás tocados, de materias distintas del amianto (asbesto). Para que se clasifiquen en esta partida, los artículos antes citados deben cumplir las dos condiciones siguientes: - tener señales apreciables de uso, y - presentarse a granel o en balas, sacos (bolsas) o acondicionamientos similares. Nota de subpartida. 1. La subpartida 6304.20 comprende los artículos confeccionados a partir de tejidos de punto por urdimbre, impregnados o recubiertos con alfa-cipermetrina (ISO), clorfenapir (ISO), deltametrina (DCI, ISO), lambda-cialotrina (ISO), permetrina (ISO) o pirimifos-metil (ISO). Nota Complementaria. 1. En la supartida 6310.10.00.10, se consideran recortes de la industria de la confección, los retazos de tejidos, nuevos, de forma irregular y dimensiones reducidas, de un mismo color y de un mismo tejido, definitivamente inservibles como tejidos a consecuencia de roturas, corte o tamaño, procedentes de la fabricación de confecciones, utilizados exclusivamente para la recuperación de las fibras textiles por deshilachado, destinadas a la fabricación de hilados, presentados en balas o sacos. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 225', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (64, 'Capítulo', NULL, 64, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los artículos desechables para cubrir los pies o el calzado, de materiales livianos o poco resistentes (por ejemplo: papel, hojas de plástico) y sin suela aplicada (régimen de la materia constitutiva); b) el calzado de materia textil, sin suela exterior encolada, cosida o fijada o aplicada de otro modo a la parte superior (Sección XI); c) el calzado usado de la partida 63.09; d) los artículos de amianto (asbesto) (partida 68.12); e) el calzado y aparatos de ortopedia, y sus partes (partida 90.21); f) el calzado que tenga el carácter de juguete y el calzado con patines fijos (para hielo o de ruedas); espinilleras (canilleras) y demás artículos de protección utilizados en la práctica del deporte (Capítulo 95). 2. En la partida 64.06, no se consideran partes las clavijas (estaquillas), protectores, anillos para ojetes, ganchos, hebillas, galones, borlas, cordones y demás artículos de ornamentación o de pasamanería, que siguen su propio régimen, ni los botones para el calzado (partida 96.06). 3. En este Capítulo: a) los términos caucho y plástico comprenden los tejidos y demás soportes textiles con una capa exterior de caucho o plástico perceptible a simple vista; a los efectos de esta disposición, se hará abstracción de los cambios de color producidos por las operaciones de obtención de esta capa exterior; b) la expresión cuero natural se refiere a los productos de las partidas 41.07 y 41.12 a 41.14 4. Sin perjuicio de lo dispuesto en la Nota 3 de este Capítulo: a) la materia de la parte superior será la que constituya la superficie mayor de recubrimiento exterior, sin considerar los accesorios o refuerzos, tales como ribetes, protectores de tobillos, adornos, hebillas, orejas, anillos para ojetes o dispositivos análogos; b) la materia constitutiva de la suela será aquella cuya superficie en contacto con el suelo sea la mayor, sin considerar los accesorios o refuerzos, tales como puntas, tiras, clavos, protectores o dispositivos análogos. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 227', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (65, 'Capítulo', NULL, 65, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los sombreros y demás tocados usados de la partida 63.09; b) los sombreros y demás tocados de amianto (asbesto) (partida 68.12); c) los sombreros y demás tocados que tengan el carácter de juguetes, tales como los sombreros para muñecas y los artículos para fiestas (Capítulo 95). 2. La partida 65.02 no comprende los cascos o formas confeccionados por costura, excepto los que se obtienen por unión de tiras simplemente cosidas en espiral. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 229', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (66, 'Capítulo', NULL, 66, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los bastones medida y similares (partida 90.17); b) los bastones escopeta, bastones estoque, bastones plomados y similares (Capítulo 93); c) los artículos del Capítulo 95 (por ejemplo: los paraguas y sombrillas manifiestamente destinados al entretenimiento de los niños). 2. La partida 66.03 no comprende los accesorios de materia textil, las vainas, fundas, borlas, dragonas y similares, de cualquier materia, para los artículos de las partidas 66.01 o 66.02. Estos accesorios se clasifican separadamente, incluso cuando se presenten con los artículos a los que se destinen, pero sin montar en dichos artículos.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (67, 'Capítulo', NULL, 67, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las telas filtrantes y capachos, de cabello (partida 59.11); b) los motivos florales de encaje, bordados u otros tejidos (Sección XI); c) el calzado (Capítulo 64); d) los sombreros y demás tocados y las redecillas para el cabello (Capítulo 65); e) los juguetes, artefactos deportivos y artículos para carnaval (Capítulo 95); f) los plumeros, borlas y similares para la aplicación de polvos y los cedazos de cabello (Capítulo 96). 2. La partida 67.01 no comprende: a) los artículos en los que las plumas o plumón sean únicamente material de relleno y, en particular, los artículos de cama de la partida 94.04; b) las prendas y complementos (accesorios), de vestir, en los que las plumas o plumón sean simples adornos o material de relleno; c) las flores, follaje, y sus partes y los artículos confeccionados de la partida 67.02. 3. La partida 67.02 no comprende: a) los artículos de vidrio (Capítulo 70); b) las imitaciones de flores, follaje o frutos, de cerámica, piedra, metal, madera, etc., obtenidas en una sola pieza por moldeo, forjado, cincelado, estampado o por cualquier otro procedimiento, ni las formadas por varias partes unidas por procedimientos distintos del atado, encolado, encajado o similares. 230 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (68, 'Capítulo', NULL, 68, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los artículos del Capítulo 25; b) el papel y cartón estucados, recubiertos, impregnados o revestidos de las partidas 48.10 o 48.11 (por ejemplo: los revestidos de polvo de mica o grafito, el papel y cartón embetunados o asfaltados); c) los tejidos y otras superficies textiles recubiertos, impregnados o revestidos de los Capítulos 56 o 59 (por ejemplo: los revestidos de polvo de mica, de betún, de asfalto); d) los artículos del Capítulo 71; e) las herramientas y partes de herramientas del Capítulo 82; f) las piedras litográficas de la partida 84.42; g) los aisladores eléctricos (partida 85.46) y las piezas aislantes de la partida 85.47; h) las pequeñas muelas para tornos de dentista (partida 90.18); ij) los artículos del Capítulo 91 (por ejemplo: cajas y envolturas similares de relojes u otros aparatos de relojería); k) los artículos del Capítulo 94 (por ejemplo: muebles, luminarias y aparatos de alumbrado, construcciones prefabricadas); l) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos); m) los artículos de la partida 96.02, cuando estén constituidos por las materias mencionadas en la Nota 2 b) del Capítulo 96, los artículos de la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (69, 'Capítulo', NULL, 69, 'Varios', 'Notas. 1. Este Capítulo solo comprende los productos cerámicos cocidos después de darles forma: a) las partidas 69.04 a 69.14 comprenden exclusivamente los productos que no puedan clasificarse en las partidas 69.01 a 69.03; b) no se pueden considerar cocidos los productos que se han calentado a temperaturas inferiores a 800 °C para provocar el endurecimiento de las resinas que contienen, la aceleración de las reacciones de hidratación o la eliminación de agua o de otras sustancias volátiles eventualmente presentes. Estos productos están excluidos del Capítulo 69; c) los artículos cerámicos se obtienen cociendo materias no metálicas inorgánicas después de haberlas preparado y de darles forma previamente, normalmente a temperatura ambiente. Las materias primas utilizadas son entre otras la arcilla, materias silíceas (incluida la sílice fundida), materias con punto de fusión elevado tales como los óxidos, carburos, nitruros, grafito u otros carbonos y, en algunos casos, aglomerantes tales como arcillas refractarias y fosfatos. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 233', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (70, 'Capítulo', NULL, 70, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los artículos de la partida 32.07 (por ejemplo: composiciones vitrificables, frita de vidrio y demás vidrios, en polvo, gránulos, copos o escamillas); b) los artículos del Capítulo 71 (por ejemplo, bisutería); c) los cables de fibras ópticas de la partida 85.44, los aisladores eléctricos (partida 85.46) y las piezas aislantes de la partida 85.47; d) los parabrisas, vidrios traseros (lunetas)* y demás ventanillas, enmarcados, para vehículos de los Capítulos 86 a 88; e) los parabrisas, vidrios traseros (lunetas)* y demás ventanillas, incluso enmarcados, que incorporen dispositivos de calefacción u otros dispositivos eléctricos o electrónicos, para vehículos de los Capítulos 86 a 88; f) las fibras ópticas, elementos de óptica trabajados ópticamente, jeringas, ojos artificiales, así como termómetros, barómetros, areómetros, densímetros y demás artículos e instrumentos del Capítulo 90; g) las luminarias y los aparatos de alumbrado, los anuncios, letreros y placas indicadoras, luminosos y artículos similares, con fuente de luz inseparable, así como sus partes, de la partida 94.05; h) los juegos, juguetes y accesorios para árboles de Navidad, así como los demás artículos del Capítulo 95, excepto los ojos sin mecanismo para muñecas o demás artículos del Capítulo 95; ij) los botones, pulverizadores, termos y demás artículos del Capítulo 96. 2. En las partidas 70.03, 70.04 y 70.05: a) el vidrio elaborado antes del recocido no se considera trabajado; b) el corte en cualquier forma no afecta la clasificación del vidrio en placas u hojas; c) se entiende por capa absorbente, reflectante o antirreflectante, la capa metálica o de compuestos químicos (por ejemplo, óxidos metálicos), de espesor microscópico que absorbe, en particular, los rayos infrarrojos o mejora las cualidades reflectantes del vidrio sin impedir su transparencia o translucidez o que impide que la superficie del vidrio refleje la luz. 3. Los productos de la partida 70.06 permanecen clasificados en dicha partida, aunque tengan ya el carácter de manufacturas. 4. En la partida 70.19, se entiende por lana de vidrio: a) la lana mineral con un contenido de sílice (SiO2) superior o igual al 60 % en peso; b) la lana mineral con un contenido de sílice (SiO2) inferior al 60 % en peso, pero con un contenido de óxidos alcalinos (K2O u Na2O) superior al 5 % en peso o con un contenido de anhídrido bórico (B2O3) superior al 2 % en peso. Las lanas minerales que no cumplan estas condiciones se clasifican en la partida 68.06. 5. En la Nomenclatura, el cuarzo y demás sílices, fundidos, se consideran vidrio. Nota de subpartida. 1. En las subpartidas 7013.22, 7013.33, 7013.41 y 7013.91, la expresión cristal al plomo solo comprende el vidrio con un contenido de monóxido de plomo (PbO) superior o igual al 24 % en peso. 236 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (71, 'Capítulo', NULL, 71, 'Varios', 'Notas. 1. Sin perjuicio de la aplicación de la Nota 1 A) de la Sección VI y de las excepciones previstas a continuación, se incluye en este Capítulo cualquier artículo compuesto total o parcialmente: a) de perlas naturales (finas)* o cultivadas, de piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas); o b) de metal precioso o de chapado de metal precioso (plaqué). 2. A) Las partidas 71.13, 71.14 y 71.15 no comprenden los artículos en los que el metal precioso o el chapado de metal precioso (plaqué) sean únicamente simples accesorios o adornos de mínima importancia (por ejemplo: iniciales, monogramas, virolas, orlas); el apartado b) de la Nota 1 anterior no incluye estos artículos. B) En la partida 71.16 solo se clasifican los artículos que no lleven metal precioso ni chapado de metal precioso (plaqué) o que, llevándolos, solo sean simples accesorios o adornos de mínima importancia. 3. Este Capítulo no comprende: a) las amalgamas de metal precioso y el metal precioso en estado coloidal (partida 28.43); b) las ligaduras estériles para suturas quirúrgicas, los productos de obturación dental y demás artículos del Capítulo 30; c) los productos del Capítulo 32 (por ejemplo, abrillantadores (lustres) líquidos); d) los catalizadores sobre soporte (partida 38.15); e) los artículos de las partidas 42.02 y 42.03, a los que se refiere la Nota 3 B) del Capítulo 42; f) los artículos de las partidas 43.03 o 43.04; g) los productos de la Sección XI (materias textiles y sus manufacturas); h) el calzado, los sombreros y demás tocados y otros artículos de los Capítulos 64 o 65; 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 239', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (72, 'Capítulo', NULL, 72, 'Varios', 'Notas. 1. En este Capítulo y, respecto a los apartados d), e) y f) de esta Nota, en toda la Nomenclatura, se consideran: a) Fundición en bruto las aleaciones hierro-carbono que no se presten prácticamente a la deformación plástica, con un contenido de carbono superior al 2 % en peso, incluso con otro u otros elementos en las proporciones en peso siguientes: - inferior o igual al 10 % de cromo - inferior o igual al 6 % de manganeso - inferior o igual al 3 % de fósforo - inferior o igual al 8 % de silicio - inferior o igual al 10 % , en total, de los demás elementos. b) Fundición especular las aleaciones hierro-carbono con un contenido de manganeso superior al 6 % pero inferior o igual al 30 % , en peso, siempre que las demás características respondan a la definición de la Nota 1 a). c) Ferroaleaciones las aleaciones en lingotes, bloques, masas o formas primarias similares, en formas obtenidas por colada continua o en granallas o en polvo, incluso aglomerados, corrientemente utilizadas en la siderurgia como productos de aporte para la preparación de otras aleaciones, o como desoxidantes, desulfurantes o en usos similares y que no se presten generalmente a la deformación plástica, con un contenido de hierro superior o igual al 4 % en peso y con uno o varios elementos en las proporciones en peso siguientes: - superior al 10 % de cromo - superior al 30 % de manganeso - superior al 3 % de fósforo - superior al 8 % de silicio - superior al 10 % , en total, de los demás elementos, excepto el carbono, sin que el porcentaje de cobre sea superior al 10 % . d) Acero las materias férreas, excepto las de la partida 72.03 que, salvo determinados tipos de aceros producidos en forma de piezas moldeadas, se presten a la deformación plástica y con un contenido de carbono inferior o igual al 2 % en peso. Sin embargo, los aceros al cromo pueden tener un contenido de carbono más elevado. e) Acero inoxidable el acero aleado con un contenido de carbono inferior o igual al 1,2 % en peso y de cromo superior o igual al 10,5 % en peso, incluso con otros elementos. f) Los demás aceros aleados los aceros que no respondan a la definición de acero inoxidable y que contengan uno o varios de los elementos indicados a continuación en las proporciones en peso siguientes: - superior o igual al 0,3 % de aluminio - superior o igual al 0,0008 % de boro - superior o igual al 0,3 % de cromo - superior o igual al 0,3 % de cobalto - superior o igual al 0,4 % de cobre - superior o igual al 0,4 % de plomo - superior o igual al 1,65 % de manganeso - superior o igual al 0,08 % de molibdeno - superior o igual al 0,3 % de níquel - superior o igual al 0,06 % de niobio - superior o igual al 0,6 % de silicio - superior o igual al 0,05 % de titanio - superior o igual al 0,3 % de volframio (tungsteno) - superior o igual al 0,1 % de vanadio - superior o igual al 0,05 % de circonio - superior o igual al 0,1 % de los demás elementos considerados individualmente (excepto el azufre, fósforo, carbono y nitrógeno). g) Lingotes de chatarra de hierro o de acero los productos colados groseramente en forma de lingotes sin mazarotas o de bloques, que presenten defectos profundos en la superficie y no respondan, en su composición química, a las definiciones de fundición en bruto, de fundición especular o de ferroaleaciones. 8. En esta Sección, se entiende por: a) Desperdicios y desechos 1°) todos los desperdicios y desechos metálicos; 2°) las manufacturas de metal definitivamente inservibles como tales a consecuencia de rotura, corte, desgaste u otra causa. b) Polvos El producto que pase por un tamiz con abertura de malla de 1 mm en proporción superior o igual al 90 % en peso. 9. En los Capítulos 74 a 76 y 78 a 81, se entiende por: a) Barras los productos laminados, extrudidos, estirados o forjados, sin enrollar, cuya sección transversal, maciza y constante en toda su longitud, tenga forma de círculo, óvalo, cuadrado, rectángulo, triángulo equilátero o polígono regular convexo (incluidos los círculos aplanados y los rectángulos modificados, en los que dos lados opuestos tengan forma de arco convexo y los otros dos sean rectos, iguales y paralelos). Los productos de sección transversal cuadrada, rectangular, triangular o poligonal, pueden tener las aristas redondeadas en toda su longitud. El espesor de los productos de sección transversal rectangular (incluidos los de sección rectangular modificada) debe ser superior a la décima parte de la anchura. También se consideran barras, los productos de las mismas formas y dimensiones, moldeados, colados o sinterizados, que han recibido, después de su obtención, un trabajo superior a un desbarbado grosero, siempre que este trabajo no confiera a los productos el carácter de artículos o manufacturas comprendidos en otra parte. Sin embargo, las barras para alambrón («wire-bars») y los tochos, del Capítulo 74, apuntados o simplemente trabajados de otro modo en sus extremos, para facilitar su introducción en las máquinas para transformarlos, por ejemplo, en alambrón o en tubos, se consideran cobre en bruto de la partida 74.03. Esta disposición se aplica mutatis mutandis a los productos del Capítulo 81. b) Perfiles los productos laminados, extrudidos, estirados, forjados u obtenidos por conformado o plegado, enrollados o sin enrollar, de sección transversal constante en toda su longitud, que no cumplan las definiciones de barras, alambre, chapas, hojas, tiras o tubos. También se consideran perfiles, los productos de las mismas formas, moldeados, colados o sinterizados, que han recibido, después de su obtención, un trabajo superior a un desbarbado grosero, siempre que este trabajo no confiera a los productos el carácter de artículos o manufacturas comprendidos en otra parte. c) Alambre el producto laminado, extrudido o trefilado, enrollado, cuya sección transversal maciza y constante en toda su longitud, tenga forma de círculo, óvalo, cuadrado, rectángulo, triángulo equilátero o polígono regular convexo (incluidos los círculos aplanados y los rectángulos modificados, en los que dos lados opuestos tengan forma de arco convexo y los otros dos sean rectos, iguales y paralelos). Los productos de sección transversal cuadrada, rectangular, triangular o poligonal, pueden tener las aristas redondeadas en toda su longitud. El espesor de los productos de sección transversal rectangular (incluidos los de sección rectangular modificada) debe ser superior a la décima parte de la anchura. d) Chapas, hojas y tiras 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 243', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (73, 'Capítulo', NULL, 73, 'Varios', 'Notas. 1. En este Capítulo, se entiende por fundición el producto obtenido por moldeo que no responda a la composición química del acero definido en la Nota 1 d) del Capítulo 72, en el que el hierro predomine en peso sobre cada uno de los demás elementos. 2. En este Capítulo, el término alambre se refiere a los productos obtenidos en caliente o en frío cuya sección transversal, cualquiera que fuese su forma, sea inferior o igual a 16 mm en su mayor dimensión. 252 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (74, 'Capítulo', NULL, 74, 'Varios', 'Nota. 1. En este Capítulo, se entiende por: a) Cobre refinado el metal con un contenido de cobre superior o igual al 99,85 % en peso; o el metal con un contenido de cobre superior o igual al 97,5 % en peso, siempre que el contenido de cualquier otro elemento sea inferior o igual a los límites indicados en el cuadro siguiente: CUADRO - Otros elementos Elemento Contenido límite % en peso Ag Plata 0,25 As Arsénico 0,5 Cd Cadmio 1,3 Cr Cromo 1,4 Mg Magnesio 0,8 Pb Plomo 1,5 S Azufre 0,7 Sn Estaño 0,8 Te Telurio 0,8 Zn Cinc 1 Zr Circonio 0,3 Los demás elementos*, cada uno 0,3 * Los demás elementos, por ejemplo: Al, Be, Co, Fe, Mn, Ni, Si. b) Aleaciones de cobre las materias metálicas, excepto el cobre sin refinar, en las que el cobre predomine en peso sobre cada uno de los demás elementos, siempre que: 1) el contenido en peso de, al menos, uno de los demás elementos sea superior a los límites indicados en el cuadro anterior; o 2) el contenido total de los demás elementos sea superior al 2,5 % en peso. c) Aleaciones madre de cobre las composiciones que contengan cobre en proporción superior al 10 % en peso y otros elementos, que no se presten a la deformación plástica y se utilicen como productos de aporte en la preparación de otras aleaciones o como desoxidantes, desulfurantes o usos similares en la metalurgia de los metales no férreos. Sin embargo, las combinaciones fósforo y cobre (cuprofósforos) con un contenido de fósforo superior al 15 % en peso, se clasifican en la partida 28.53. Nota de subpartida. 1. En este Capítulo, se entiende por: a) Aleaciones a base de cobre-cinc (latón) las aleaciones de cobre y cinc, incluso con otros elementos. Cuando estén presentes otros elementos: - el cinc debe predominar en peso sobre cada uno de los demás elementos; - el contenido eventual de níquel debe ser inferior al 5 % en peso (véanse las aleaciones a base de cobre-níquel-cinc (alpaca)); - el contenido eventual de estaño debe ser inferior al 3 % en peso (véanse las aleaciones a base de cobre-estaño (bronce)). b) Aleaciones a base de cobre-estaño (bronce) las aleaciones de cobre y estaño, incluso con otros elementos. Cuando estén presentes otros elementos, el estaño debe predominar en peso sobre cada uno de estos otros elementos. Sin embargo, cuando el contenido de estaño sea superior o igual al 3 % en peso, el de cinc puede predominar, pero debe ser inferior al 10 % en peso. c) Aleaciones a base de cobre-níquel-cinc (alpaca) las aleaciones de cobre, níquel y cinc, incluso con otros elementos. El contenido de níquel debe ser superior o igual al 5 % en peso (véanse las aleaciones a base de cobre-cinc (latón)). d) Aleaciones a base de cobre-níquel las aleaciones de cobre y níquel, incluso con otros elementos, pero que, en ningún caso, el contenido de cinc sea superior al 1 % en peso. Cuando estén presentes otros elementos, el níquel debe predominar en peso sobre cada uno de estos otros elementos. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 257', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (75, 'Capítulo', NULL, 75, 'Varios', 'Notas de subpartida. 1. En este Capítulo, se entiende por: a) Níquel sin alear el metal con un contenido total de níquel y de cobalto superior o igual al 99 % en peso, siempre que: 1) el contenido de cobalto sea inferior o igual al 1,5 % en peso, y 2) el contenido de cualquier otro elemento sea inferior o igual a los límites que figuran en el cuadro siguiente: CUADRO - Otros elementos Elemento Contenido límite % en peso Fe Hierro O Oxígeno Los demás elementos, cada uno 0,5 0,4 0,3 b) Aleaciones de níquel las materias metálicas en las que el níquel predomine en peso sobre cada uno de los demás elementos, siempre que: 1) el contenido de cobalto sea superior al 1,5 % en peso; 2) el contenido en peso de, al menos, uno de los demás elementos sea superior a los límites indicados en el cuadro anterior; o 3) el contenido total de elementos distintos del níquel y del cobalto sea superior al 1 % en peso. 2. No obstante lo dispuesto en la Nota 9 c) de la Sección XV, en la subpartida 7508.10, solamente se admite como alambre el producto, enrollado o sin enrollar, cuya sección transversal, de cualquier forma, sea inferior o igual a 6 mm en su mayor dimensión. 260 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (76, 'Capítulo', NULL, 76, 'Varios', 'Notas de subpartida. 1. En este Capítulo, se entiende por: a) Aluminio sin alear el metal con un contenido de aluminio superior o igual al 99 % en peso, siempre que el contenido en peso de los demás elementos sea inferior o igual a los límites indicados en el cuadro siguiente: CUADRO - Otros elementos Elemento Contenido límite % en peso Fe+Si (total hierro más silicio) Los demás elementos 1), cada uno 1 0,1 2) 1) Los demás elementos, por ejemplo: Cr, Cu, Mg, Mn, Ni, Zn. 2) Se tolera un contenido de cobre superior al 0,1 % pero inferior o igual al 0,2 % , siempre que ni el contenido de cromo ni el de manganeso sea superior al 0,05 % b) Aleaciones de aluminio las materias metálicas en las que el aluminio predomine en peso sobre cada uno de los demás elementos, siempre que: 1) el contenido en peso de, al menos, uno de los demás elementos o el total hierro más silicio, sea superior a los límites indicados en el cuadro anterior; o 2) el contenido total de los demás elementos sea superior al 1 % en peso. 2. No obstante lo dispuesto en la Nota 9 c) de la Sección XV, en la subpartida 7616.91, solamente se admite como alambre el producto, enrollado o sin enrollar, cuya sección transversal, de cualquier forma, sea inferior o igual a 6 mm en su mayor dimensión. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 261', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (78, 'Capítulo', NULL, 78, 'Varios', 'Nota de subpartida. 1. En este Capítulo, se entiende por plomo refinado: el metal con un contenido de plomo superior o igual al 99,9 % en peso, siempre que el contenido en peso de cualquier otro elemento sea inferior o igual a los límites indicados en el cuadro siguiente: 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 263', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (79, 'Capítulo', NULL, 79, 'Varios', 'Nota de subpartida. 1. En este Capítulo, se entiende por: a) Cinc sin alear el metal con un contenido de cinc superior o igual al 97,5 % en peso. b) Aleaciones de cinc las materias metálicas en las que el cinc predomine en peso sobre cada uno de los demás elementos, siempre que el contenido total de los demás elementos sea superior al 2,5 % en peso. c) Polvo de condensación, de cinc el producto obtenido por condensación de vapor de cinc constituido por partículas esféricas más finas que el polvo. Estas partículas deben pasar por un tamiz con abertura de malla de 63 micrómetros (micras, micrones)* en una proporción superior o igual al 80 % en peso. El contenido de cinc metálico debe ser superior o igual al 85 % en peso. CUADRO - Otros elementos Elemento Contenido límite % en peso Ag Plata As Arsénico Bi Bismuto Ca Calcio Cd Cadmio Cu Cobre Fe Hierro S Azufre Sb Antimonio Sn Estaño Zn Cinc Los demás (por ejemplo, Te), cada uno 0,02 0,005 0,05 0,002 0,002 0,08 0,002 0,002 0,005 0,005 0,002 0,001 264 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (80, 'Capítulo', NULL, 80, 'Varios', 'Nota de subpartida. 1. En este Capítulo, se entiende por: a) Estaño sin alear el metal con un contenido de estaño superior o igual al 99 % en peso, siempre que el contenido de bismuto o de cobre, eventualmente presentes, sea inferior en peso a los límites indicados en el cuadro siguiente: CUADRO - Otros elementos Elemento Contenido límite % en peso Bi Bismuto Cu Cobre 0,1 0,4 b) Aleaciones de estaño las materias metálicas en las que el estaño predomine en peso sobre cada uno de los demás elementos, siempre que: 1) el contenido total de los demás elementos sea superior al 1 % en peso; o 2) el contenido de bismuto o cobre sea superior o igual en peso a los límites indicados en el cuadro anterior. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 265', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (82, 'Capítulo', NULL, 82, 'Varios', 'Notas. 1. Independientemente de las lámparas de soldar, de las fraguas portátiles, de las muelas con bastidor y de los juegos de manicura o pedicuro, así como de los artículos de la partida 82.09, este Capítulo comprende solamente los artículos provistos de una hoja u otra parte operante: a) de metal común; b) de carburo metálico o de cermet; c) de piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas), con soporte de metal común, carburo metálico o cermet; d) de abrasivos con soporte de metal común, siempre que se trate de útiles cuyos dientes, aristas u otras partes cortantes no hayan perdido su función propia por la presencia de polvo abrasivo. 2. Las partes de metal común de los artículos de este Capítulo se clasifican con los mismos, excepto las partes especialmente citadas y los portaútiles para herramientas de mano de la partida 84.66. Sin embargo, siempre se excluyen de este Capítulo las partes o accesorios de uso general, tal como se definen en la Nota 2 de esta Sección. Se excluyen de este Capítulo, las cabezas, peines, contrapeines, hojas y cuchillas de afeitadoras, cortadoras de pelo o esquiladoras, eléctricas (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (83, 'Capítulo', NULL, 83, 'Varios', 'Notas. 1. En este Capítulo, las partes de metal común se clasifican en la partida correspondiente a los artículos a los que pertenecen. Sin embargo, no se consideran partes de manufacturas de este Capítulo, los artículos de fundición, hierro o acero de las partidas 73.12, 73.15, 73.17, 73.18 o 73.20 ni los mismos artículos de otro metal común (Capítulos 74 a 76 y 78 a 81). 2. En la partida 83.02, se consideran ruedas las que tengan un diámetro (incluido el bandaje, en su caso) inferior o igual a 75 mm o las de mayor diámetro (incluido el bandaje, en su caso) siempre que la anchura de la rueda o del bandaje que se les haya montado sea inferior a 30 mm. 270 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (84, 'Capítulo', NULL, 84, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las muelas y artículos similares para moler y demás artículos del Capítulo 68; b) las máquinas, aparatos o artefactos (por ejemplo, bombas), de cerámica y las partes de cerámica de las máquinas, aparatos o artefactos de cualquier materia (Capítulo 69); c) los artículos de vidrio para laboratorio (partida 70.17); los artículos de vidrio para usos técnicos (partidas 70.19 o 70.20); d) los artículos de las partidas 73.21 ó 73.22, así como los artículos similares de otros metales comunes (Capítulos 74 a 76 o 78 a 81); e) las aspiradoras de la partida 85.08; f) los aparatos electromecánicos de uso doméstico de la partida 85.09; las cámaras digitales de la partida 85.25; g) los radiadores para los artículos de la Sección XVII; h) las escobas mecánicas de uso manual, excepto las de motor (partida 96.03). 2. Salvo lo dispuesto en la Nota 3 de la Sección XVI y la Nota 11 del presente Capítulo, las máquinas y aparatos susceptibles de clasificarse a la vez tanto en las partidas 84.01 a 84.24 o en la partida 84.86, como en las partidas 84.25 a 84.80, se clasifican en las partidas 84.01 a 84.24 o en la partida 84.86, según el caso. Sin embargo, A) no se clasifican en la partida 84.19: 1°) las incubadoras y criadoras avícolas y los armarios y estufas de germinación (partida 84.36); 2°) los aparatos humectadores de granos para la molinería (partida 84.37); 3°) los difusores para la industria azucarera (partida 84.38); 4°) las máquinas y aparatos para tratamiento térmico de hilados, tejidos o manufacturas de materia textil (partida 84.51); 5°) los aparatos, dispositivos o equipos de laboratorio diseñados para realizar una operación mecánica, en los que el cambio de temperatura, aunque necesario, solo desempeñe una función accesoria. B) no se clasifican en la partida 84.22: 1°) las máquinas de coser para cerrar envases (partida 84.52); 2°) las máquinas y aparatos de oficina de la partida 84.72. C) no se clasifican en la partida 84.24: 1°) las máquinas para imprimir por chorro de tinta (partida 84.43); 2°) las máquinas para cortar por chorro de agua (partida 84.56). 3. Las máquinas herramienta que trabajen por arranque de cualquier materia susceptibles de clasificarse a la vez tanto en la partida 84.56 como en las partidas', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (85, 'Capítulo', NULL, 85, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las mantas, cojines, calientapiés y artículos similares, que se calienten eléctricamente; las prendas de vestir, calzado, orejeras y demás artículos que se lleven sobre la persona, calentados eléctricamente; b) las manufacturas de vidrio de la partida 70.11; c) las máquinas y aparatos de la partida 84.86; d) las aspiradoras de los tipos utilizados en medicina, cirugía, odontología o veterinaria (partida 90.18); e) los muebles con calentamiento eléctrico del Capítulo 94. 2. Los artículos susceptibles de clasificarse tanto en las partidas 85.01 a 85.04 como en las partidas 85.11, 85.12, 85.40, 85.41 u 85.42 se clasifican en estas cinco últimas partidas. Sin embargo, los rectificadores de vapor de mercurio de cubeta metálica permanecen clasificados en la partida 85.04. 3. En la partida 85.07, la expresión acumuladores eléctricos también comprende los acumuladores presentados con elementos auxiliares, que contribuyan a la función de almacenamiento y suministro de energía del acumulador o destinados a protegerlo de daños, tales como conectores eléctricos, dispositivos de control de temperatura (por ejemplo, termistores) y dispositivos de protección de circuitos. Pueden también incluir una parte de la carcasa de protección de los aparatos a los que están destinados. 4. La partida 85.09 comprende, siempre que se trate de aparatos electromecánicos de los tipos normalmente utilizados en usos domésticos: a) las enceradoras (lustradoras) de pisos, trituradoras y mezcladoras de alimentos y extractoras de jugo de frutos u hortalizas, de cualquier peso; b) los demás aparatos de peso inferior o igual a 20 kg, excepto los ventiladores y las campanas aspirantes para extracción o reciclado, con ventilador incorporado, incluso con filtro (partida 84.14), las secadoras centrífugas de ropa (partida 84.21), las máquinas para lavar vajilla (partida 84.22), las máquinas para lavar ropa (partida 84.50), las máquinas para planchar (partidas 84.20 u 84.51, según se trate de calandrias u otros tipos), las máquinas de coser (partida 84.52), las tijeras eléctricas (partida 84.67) y los aparatos electrotérmicos (partida 85.16). 5. En la partida 85.17, se entiende por teléfonos inteligentes los teléfonos celulares (móviles)* equipados con un sistema operativo diseñado para realizar las funciones de una máquina automática para tratamiento o procesamiento de datos, tales como la descarga y el funcionamiento simultáneo de varias aplicaciones, incluidas las aplicaciones de terceros, e incluso dotados de otras funciones tales como una cámara digital o un sistema de navegación. 6. En la partida 85.23: a) se consideran dispositivos de almacenamiento permanente de datos a base de semiconductores (por ejemplo, «tarjetas de memoria flash» o «tarjetas de memoria electrónica flash») los dispositivos de almacenamiento con un conector, que tienen, en la misma envoltura, una o más memorias flash (por ejemplo, «E2PROM FLASH») en forma de circuitos integrados montados en una tarjeta de circuitos impresos. Pueden llevar un controlador en forma de circuito integrado y componentes pasivos discretos, tales como condensadores y resistencias; b) la expresión tarjetas inteligentes («smart cards») comprende las tarjetas que tienen incluidos uno o más circuitos electrónicos integrados (un microprocesador, una memoria de acceso aleatorio (RAM) o una memoria de solo lectura (ROM)), en forma de microplaquitas (chips). Estas tarjetas pueden llevar contactos, una banda magnética o una antena integrada, pero no tienen ningún otro elemento activo o pasivo, de circuito. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 305 7. En la partida 85.24, se entiende por módulos de visualización («display») de pantalla plana los dispositivos o aparatos destinados a mostrar información, equipados con al menos una pantalla de visualización, que están diseñados para ser incorporados, antes de su utilización, en artículos comprendidos en otras partidas. Estas pantallas incluyen sin estar limitadas en su forma, a aquellas que son planas, curvas, flexibles, plegables o expandibles. Los módulos de visualización de pantalla plana pueden incorporar elementos adicionales, incluidos los necesarios para recibir señales de video y distribuir estas señales en píxeles en la pantalla. Sin embargo, la partida 85.24 no comprende los módulos de visualización equipados con componentes para convertir señales de video (por ejemplo: un circuito integrado para escalador, un circuito integrado para un decodificador o un procesador de aplicación) o que hayan obtenido el carácter de mercancías de otras partidas. Con el fin de clasificar los módulos de visualización de pantalla plana definidos en esta Nota, la partida 85.24 tiene prioridad sobre cualquier otra partida de la Nomenclatura. 8. En la partida 85.34, se consideran circuitos impresos los obtenidos disponiendo sobre un soporte aislante, por cualquier procedimiento de impresión (por ejemplo: incrustación, deposición electrolítica, grabado) o por la técnica de los circuitos de capa, elementos conductores, contactos u otros componentes impresos (por ejemplo: inductancias, resistencias, capacitancias), solos o combinados entre sí según un esquema preestablecido, excepto cualquier elemento que pueda producir, rectificar, modular o amplificar una señal eléctrica (por ejemplo, elementos semiconductores). La expresión circuitos impresos no comprende los circuitos combinados con elementos que no hayan sido obtenidos durante el proceso de impresión ni las resistencias, condensadores o inductancias discretos. Sin embargo, los circuitos impresos pueden estar provistos con elementos de conexión no impresos. Los circuitos de capa (delgada o gruesa), con elementos pasivos y activos obtenidos durante el mismo proceso tecnológico, se clasifican en la partida 85.42. 9. En la partida 85.36, se entiende por conectores de fibras ópticas, de haces o cables de fibras ópticas, los conectores que solo sirven para alinear mecánicamente las fibras ópticas extremo con extremo en un sistema de cable digital. No realizan ninguna otra función, tal como la amplificación, regeneración o modificación de la señal. 10. La partida 85.37 no comprende los mandos a distancia inalámbricos con dispositivo infrarrojo de los aparatos receptores de televisión u otros aparatos eléctricos (partida 85.43). 11. En la partida 85.39, la expresión fuentes luminosas de diodos emisores de luz (LED) comprende: a) Los módulos de diodos emisores de luz (LED) que son fuentes luminosas eléctricas basadas en diodos emisores de luz (LED), dispuestos en circuitos eléctricos y que contienen otros elementos tales como eléctricos, mecánicos, térmicos u ópticos. También contienen elementos discretos activos o pasivos o artículos de las partidas 85.36 u 85.42 con el fin de suministrar alimentación eléctrica o controlar la potencia. Los módulos de diodos emisores de luz (LED) no tienen un casquillo diseñado para permitir su fácil instalación o reemplazo en una luminaria ni para asegurar su contacto eléctrico y fijación mecánica. b) Las lámparas y tubos de diodos emisores de luz (LED) que son fuentes luminosas eléctricas constituidas por uno o más módulos de LED, contienen otros elementos tales como eléctricos, mecánicos, térmicos u ópticos. Se distinguen de los módulos de diodos emisores de luz (LED) porque tienen un casquillo diseñado para permitir su fácil instalación o reemplazo en una luminaria y para asegurar su contacto eléctrico y fijación mecánica. 12. En las partidas 85.41 y 85.42 se consideran: a)1°) Dispositivos semiconductores, los dispositivos semiconductores cuyo funcionamiento se basa en la variación de la resistividad por la acción de un campo eléctrico o los transductores basados en semiconductores. Los dispositivos semiconductores también pueden comprender el ensamblaje de varios elementos, incluso equipados con dispositivos activos o pasivos cuyas funciones son auxiliares. Los transductores basados en semiconductores, a los fines de esta definición, son sensores basados en semiconductores, actuadores basados en semiconductores, resonadores basados en semiconductores y osciladores basados en semiconductores, que son tipos de dispositivos discretos basados en semiconductores, que realizan una función intrínseca y son capaces de convertir cualquier tipo de acción o de fenómeno físico o químico, en una señal eléctrica o convertir una señal eléctrica en una acción o cualquier tipo de fenómeno físico. Todos los elementos de los transductores basados en semiconductores se combinan indivisiblemente y también pueden incluir los materiales necesarios, unidos indivisiblemente, que permitan su construcción o funcionamiento. A los fines de la presente definición: 1) La expresión basados en semiconductores significa construido o fabricado sobre un sustrato semiconductor o constituido por materiales semiconductores, fabricado por medio de tecnología de semiconductores, en los cuales el sustrato o material semiconductor desempeña un papel crítico e insustituible sobre la función y el rendimiento del transductor, y cuyo funcionamiento está basado en las propiedades semiconductoras físicas, eléctricas, químicas y ópticas. 2) Los fenómenos físicos o químicos se refieren a fenómenos, tales como la presión, las ondas sonoras, la aceleración, la vibración, el movimiento, la orientación, la tensión, la intensidad de campo magnético, la intensidad de campo eléctrico, la luz, la radiactividad, la humedad, el flujo, la concentración de productos químicos, etc. 3) Los sensores basados en semiconductores son un tipo de dispositivo semiconductor, constituido por estructuras microelectrónicas o mecánicas que se crean en la masa o en la superficie de un semiconductor y cuya función es detectar cantidades físicas o químicas y convertirlas en señales eléctricas producidas por variaciones resultantes en las propiedades eléctricas o en la deformación de la estructura mecánica. 4) Los actuadores basados en semiconductores son un tipo de dispositivo semiconductor, constituido por estructuras microelectrónicas o mecánicas que se crean en la masa o en la superficie de un semiconductor y cuya función es convertir señales eléctricas en movimiento físico. 5) Los resonadores basados en semiconductores son un tipo de dispositivo semiconductor, constituido por estructuras microelectrónicas o mecánicas que se crean en la masa o en la superficie de un semiconductor y cuya función es generar una oscilación mecánica o eléctrica de una frecuencia predefinida que depende de la geometría física de estas estructuras en respuesta a una señal eléctrica externa. 6) Los osciladores basados en semiconductores son un tipo de dispositivo semiconductor, constituido por estructuras microelectrónicas o mecánicas que se crean en la masa o en la superficie de un semiconductor y que tienen la función de generar una oscilación mecánica o eléctrica de una frecuencia predefinida que depende de la geometría física de estas estructuras. 2°) Diodos emisores de luz (LED), los dispositivos semiconductores basados en materiales semiconductores que transforman la energía eléctrica en radiaciones visibles, infrarrojas o ultravioletas, incluso conectados eléctricamente entre sí e incluso combinados con diodos de protección. Los diodos emisores de luz (LED) de la partida 85.41 no incorporan elementos con el fin de suministrar alimentación eléctrica o controlar la potencia; b) Circuitos electrónicos integrados: 1º) los circuitos integrados monolíticos en los que los elementos del circuito (diodos, transistores, resistencias, condensadores, bobinas de inductancia, etc.) se crean en la masa (esencialmente) y en la superficie de un material semiconductor (por ejemplo: silicio dopado, arseniuro de galio, silicio- germanio, fosfuro de indio), formando un todo inseparable; 2º) los circuitos integrados híbridos que reúnan de modo prácticamente inseparable, mediante interconexiones o filamentos conectores, sobre un mismo sustrato aislante (vidrio, cerámica, etc.), elementos pasivos (resistencias, condensadores, bobinas de inductancia, etc.), obtenidos por la técnica de los circuitos de capa delgada o gruesa y elementos activos (diodos, transistores, circuitos integrados monolíticos, etc.), obtenidos por la técnica de los semiconductores. Estos circuitos también pueden llevar componentes discretos; 3º) los circuitos integrados multichip, formados por dos o más circuitos integrados monolíticos, interconectados de modo prácticamente inseparable, dispuestos o no sobre uno o más sustratos aislantes, con o sin bastidor de conexión, pero sin ningún otro elemento activo o pasivo, de circuito. 4º) los circuitos integrados de componentes múltiples (MCO), que son combinaciones de uno o más circuitos integrados monolíticos, híbridos o multichip y que contengan al menos uno de los componentes siguientes: sensores, accionadores, osciladores, resonadores, de silicio, incluso combinados entre sí, o componentes que realicen las funciones de los artículos susceptibles de clasificarse en las partidas 85.32, 85.33, 85.41, o inductores susceptibles de clasificarse en la partida 85.04, reunidos de modo prácticamente indivisible en un solo cuerpo como un circuito integrado, para formar un componente del tipo utilizado para ser montado en una tarjeta de circuito impreso (PCB) u otro soporte, conectados a través de clavijas, cables, rótulas, pastillas, almohadillas o discos. A los fines de esta definición: 1. Los componentes pueden ser discretos, fabricados independientemente, luego se ensamblan en un circuito integrado de componentes múltiples (MCO) o se integran a otros componentes. 2. La expresión de silicio significa que el componente se fabrica sobre un sustrato de silicio o constituido de materias a base de silicio o fabricado en un chip de circuito integrado. 3. a) Los sensores de silicio están constituidos por estructuras microelectrónicas o mecánicas, que se crean en la masa o en la superficie de un semiconductor y cuya función es detectar fenómenos físicos o químicos y convertirlos en señales eléctricas cuando se producen variaciones de las propiedades eléctricas o una deformación de la estructura mecánica. Los fenómenos físicos o químicos se refieren a fenómenos, tales como la presión, las ondas sonoras, la aceleración, la vibración, el movimiento, la orientación, la tensión, la intensidad de campo magnético, la intensidad de campo eléctrico, la luz, la radiactividad, la humedad, el flujo, la concentración de productos químicos, etc. b) Los accionadores de silicio están constituidos por estructuras microelectrónicas y mecánicas, que se crean en la masa o en la superficie de un semiconductor y cuya función es convertir las señales eléctricas en movimiento físico. c) Los resonadores de silicio son componentes constituidos por estructuras microelectrónicas o mecánicas, que se crean en la masa o en la superficie de un semiconductor y cuya función es generar una oscilación mecánica o eléctrica de una frecuencia predefinida, que depende de la geometría física de estas estructuras en respuesta a una entrada externa. d) Los osciladores de silicio son componentes activos constituidos por estructuras microelectrónicas o mecánicas, que se crean en la masa o en la superficie de un semiconductor y cuya función es generar una oscilación mecánica o eléctrica de una frecuencia predefinida, que depende de la geometría física de estas estructuras. Para los artículos definidos en esta Nota, las partidas 85.41 y 85.42 tienen prioridad sobre cualquier otra de la Nomenclatura que pudiera comprenderlos, especialmente en razón de su función, excepto en el caso de la partida 85.23. Notas de subpartida. 1. La subpartida 8525.81 comprende únicamente las cámaras de televisión, cámaras digitales y videocámaras, ultrarrápidas, que tienen una o más de las siguientes características: - velocidad de grabación superior a 0,5 mm por microsegundo; - resolución temporal inferior o igual a 50 nanosegundos; - frecuencia de imagen superior a 225.000 cuadros por segundo. 306 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (86, 'Capítulo', NULL, 86, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las traviesas (durmientes) de madera u hormigón para vías férreas o similares y los elementos de hormigón para vías guía de aerotrenes (partidas 44.06 o 68.10); b) los elementos para vías férreas de fundición, hierro o acero de la partida 73.02; c) los aparatos eléctricos de señalización, seguridad, control o mando de la partida 85.30. 2. Se clasifican en la partida 86.07, entre otros: a) los ejes, ruedas, ejes montados (trenes de ruedas), llantas, bujes, centros y demás partes de ruedas; b) los chasis, bojes y «bissels»; c) las cajas de ejes (cajas de grasa o aceite), los dispositivos de freno de cualquier clase; d) los topes, ganchos y demás sistemas de enganche, los fuelles de intercomunicación; e) los artículos de carrocería. 3. Salvo lo dispuesto en la Nota 1 anterior, se clasifican en la partida 86.08, entre otros: a) las vías ensambladas, placas y puentes giratorios, parachoques y gálibos; b) los discos y placas móviles y semáforos, aparatos de mando para pasos a nivel o cambio de agujas, puestos de maniobra a distancia y demás aparatos mecánicos (incluso electromecánicos) de señalización, seguridad, control o mando, incluso provistos de dispositivos accesorios de alumbrado eléctrico, para vías férreas o similares, carreteras, vías fluviales, áreas o parques de estacionamiento, instalaciones portuarias o aeropuertos. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 327', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (87, 'Capítulo', NULL, 87, 'Varios', 'Notas. 1. Este Capítulo no comprende los vehículos diseñados para circular solamente sobre carriles (rieles). 2. En este Capítulo, se entiende por tractores los vehículos con motor esencialmente diseñados para tirar o empujar otros aparatos, vehículos o cargas, incluso si tienen ciertos acondicionamientos accesorios en relación con su utilización principal, que permitan el transporte de herramientas, semillas, abonos, etc. Las máquinas e instrumentos de trabajo diseñados para equipar los tractores de la partida 87.01 como material intercambiable siguen su propio régimen, aunque se presenten con el tractor, incluso si están montados sobre éste. 3. Los chasis con cabina incorporada para vehículos automóviles se clasifican en las partidas 87.02 a 87.04 y no en la partida 87.06. 4. La partida 87.12 comprende todas las bicicletas para niños. Los demás velocípedos para niños se clasifican en la partida 95.03. Nota de subpartida. 1. La subpartida 8708.22 comprende: a) los parabrisas, vidrios traseros (lunetas)* y demás ventanillas, enmarcados; b) los parabrisas, vidrios traseros (lunetas)* y demás ventanillas, incluso enmarcados, que incorporen dispositivos de calefacción u otros dispositivos eléctricos o electrónicos, siempre que estén destinados exclusiva o principalmente a vehículos automóviles de las partidas 87.01 a 87.05. Notas Complementarias. 1. A los efectos de la importación de vehículos, chasis con motor y carrocería, clasificados en las partidas 87.01, 87.02, 87.03 (excepto: 8703.10.00.00),', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (88, 'Capítulo', NULL, 88, 'Varios', 'Nota. 1. En este Capítulo, se entiende por aeronave no tripulada cualquier aeronave, distinta de las de la partida 88.01, diseñada para vuelos sin piloto a bordo. Pueden estar diseñadas para transportar una carga útil o estar equipadas con cámaras digitales u otros dispositivos integrados permanentemente, para realizar funciones de utilidad durante su vuelo. Sin embargo, la expresión aeronave no tripulada no comprende los juguetes voladores, diseñados exclusivamente para fines recreativos (partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (89, 'Capítulo', NULL, 89, 'Varios', 'Nota. 1. Los barcos incompletos o sin terminar y los cascos de barcos, aunque se presenten desmontados o sin montar, así como los barcos completos desmontados o sin montar, se clasifican en la partida 89.06 en caso de duda respecto de la clase de barco a que pertenecen. 336 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (90, 'Capítulo', NULL, 90, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los artículos para usos técnicos, de caucho vulcanizado sin endurecer (partida 40.16), cuero natural o cuero regenerado (partida 42.05) o materia textil (partida 59.11); b) los cinturones, fajas y demás artículos de materia textil cuyo efecto sea sostener o mantener un órgano como única consecuencia de su elasticidad (por ejemplo: fajas de maternidad, torácicas o abdominales, vendajes para articulaciones o músculos) (Sección XI); c) los productos refractarios de la partida 69.03; los artículos para usos químicos u otros usos técnicos de la partida 69.09; d) los espejos de vidrio sin trabajar ópticamente de la partida 70.09 y los espejos de metal común o metal precioso, que no tengan las características de elementos de óptica (partida 83.06 o Capítulo 71); e) los artículos de vidrio de las partidas 70.07, 70.08, 70.11, 70.14, 70.15 o 70.17; f) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y artículos similares de plástico (Capítulo 39); sin embargo, los artículos especialmente diseñados para ser utilizados exclusivamente como implantes de uso médico, quirúrgico, odontológico o veterinario se clasifican en la partida 90.21; 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 337', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (91, 'Capítulo', NULL, 91, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los cristales para aparatos de relojería y pesas para relojes (régimen de la materia constitutiva); b) las cadenas de reloj (partidas 71.13 o 71.17, según los casos); c) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39) o de metal precioso o chapado de metal precioso (plaqué), generalmente de la partida 71.15; los muelles (resortes) de aparatos de relojería (incluidas las espirales) se clasifican, sin embargo, en la partida 91.14; d) las bolas de rodamiento (partidas 73.26 u 84.82, según los casos); e) los artículos de la partida 84.12 construidos para funcionar sin escape; f) los rodamientos de bolas (partida 84.82); g) los artículos del Capítulo 85 sin montar aún entre sí o con otros elementos para formar mecanismos de relojería o partes reconocibles como destinadas, exclusiva o principalmente, a tales mecanismos (Capítulo 85). 2. Se clasifican únicamente en la partida 91.01 los relojes con caja totalmente de metal precioso o chapado de metal precioso (plaqué) o de estas materias combinadas con perlas finas (naturales)* o cultivadas o con piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas), de las partidas', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (92, 'Capítulo', NULL, 92, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39); b) los micrófonos, amplificadores, altavoces (altoparlantes), auriculares, interruptores, estroboscopios y demás instrumentos, aparatos y equipos accesorios utilizados con los artículos de este Capítulo, que no estén incorporados en ellos ni alojados en la misma envoltura (Capítulos 85 o 90); 350 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (93, 'Capítulo', NULL, 93, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los cebos y cápsulas fulminantes, detonadores, cohetes de señales o granífugos y demás artículos del Capítulo 36; b) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39); c) los tanques y demás vehículos automóviles blindados de combate (partida 87.10); d) las miras telescópicas y demás dispositivos ópticos, salvo los montados en armas o presentados sin montar con las armas a las cuales se destinen (Capítulo 90); e) las ballestas, arcos y flechas para tiro, armas embotonadas para esgrima y armas que presenten el carácter de juguete (Capítulo 95); f) las armas y municiones que presenten el carácter de objetos de colección o antigüedades (partidas 97.05 o 97.06). 2. En la partida 93.06, el término partes no comprende los aparatos de radio o radar de la partida 85.26. c) los instrumentos y aparatos que presenten el carácter de juguete (partida 95.03); d) las escobillas y demás artículos de cepillería para limpieza de instrumentos musicales (partida 96.03) y los monopies, bípodes, trípodes y artículos similares (partida 96.20); e) los instrumentos y aparatos que presenten el carácter de objetos de colección o antigüedades (partidas 97.05 o 97.06). 2. Los arcos, palillos y artículos similares para instrumentos musicales de las partidas 92.02 o 92.06, que se presenten en número correspondiente a los instrumentos a los cuales se destinen, se clasifican con ellos. Las tarjetas, discos y rollos de la partida 92.09 se clasifican en esta partida, aunque se presenten con los instrumentos o aparatos a los que estén destinados. 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 351', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (94, 'Capítulo', NULL, 94, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los colchones, almohadas y cojines, neumáticos o de agua, de los Capítulos 39, 40 o 63; b) los espejos que se apoyen en el suelo (por ejemplo, espejos de vestir móviles) (partida 70.09); c) los artículos del Capítulo 71; d) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39) ni las cajas de caudales de la partida 83.03; e) los muebles, incluso sin equipar, que constituyan partes específicas de aparatos para la producción de frío de la partida 84.18; los muebles especialmente diseñados para máquinas de coser, de la partida 84.52; f) las fuentes luminosas y los aparatos de alumbrado, y sus partes del Capítulo 85; g) los muebles que constituyan partes específicas de aparatos de las partidas 85.18 (partida 85.18), 85.19 u 85.21 (partida 85.22) o de las partidas', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (95, 'Capítulo', NULL, 95, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) las velas (partida 34.06); b) los artículos de pirotecnia para diversión de la partida 36.04; c) los hilados, monofilamentos, cordones, cuerdas de tripa y similares para la pesca, incluso cortados en longitudes determinadas pero sin montar en sedal (tanza) con anzuelo, del Capítulo 39, partida 42.06 o Sección XI; d) las bolsas para artículos de deporte y demás continentes, de las partidas 42.02, 43.03 o 43.04; e) los disfraces de materia textil, de los Capítulos 61 o 62; las prendas de vestir de deporte y prendas especiales de materia textil, de los Capítulos 61 o 62, incluso las que incorporen accesoriamente elementos de protección, tales como placas protectoras o acolchado en las partes correspondientes a los codos, las rodillas o la ingle (por ejemplo: prendas para esgrima o suéteres (jerseys) para porteros (arqueros)* de fútbol); f) las banderas y cuerdas de gallardetes, de materia textil, así como las velas para embarcaciones, deslizadores o vehículos terrestres, del Capítulo 63; g) el calzado (excepto el fijado a patines para hielo o patines de ruedas) del Capítulo 64 y los tocados especiales para la práctica de deportes del Capítulo 65; h) los bastones, fustas, látigos y artículos similares (partida 66.02), así como sus partes (partida 66.03); ij) los ojos de vidrio sin montar para muñecas, muñecos u otros juguetes de la partida 70.18; 354 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (96, 'Capítulo', NULL, 96, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los lápices de maquillaje o tocador (Capítulo 33); b) los artículos del Capítulo 66 (por ejemplo: partes de paraguas o bastones); c) la bisutería (partida 71.17); d) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39); e) los artículos del Capítulo 82 (útiles, artículos de cuchillería, cubiertos de mesa) con mangos o partes de materias para tallar o moldear. Cuando se presenten aisladamente, estos mangos y partes se clasifican en las partidas 96.01 o 96.02; f) los artículos del Capítulo 90 (por ejemplo: monturas (armazones) de gafas (anteojos) (partida 90.03), tiralíneas (partida 90.17), artículos de cepillería de los tipos manifiestamente utilizados en medicina, cirugía, odontología o veterinaria (partida 90.18)); g) los artículos del Capítulo 91 (por ejemplo: cajas y envolturas similares de relojes o demás aparatos de relojería); h) los instrumentos musicales, sus partes y accesorios (Capítulo 92); ij) los artículos del Capítulo 93 (armas y sus partes); k) los artículos del Capítulo 94 (por ejemplo: muebles, luminarias y aparatos de alumbrado); l) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos); m) los artículos del Capítulo 97 (objetos de arte o colección y antigüedades). 2. En la partida 96.02, se entiende por materias vegetales o minerales para tallar: a) las semillas duras, pepitas, cáscaras, nueces y materias vegetales similares para tallar (por ejemplo: nuez de corozo, de palmera-dum); b) el ámbar (succino) y la espuma de mar, naturales o reconstituidos, así como el azabache y materias minerales análogas al azabache. 3. En la partida 96.03, se consideran cabezas preparadas los mechones de pelo, fibra vegetal u otra materia, sin montar, listos para su uso en la fabricación de brochas, pinceles o artículos análogos, sin dividirlos o que solo necesiten un complemento poco importante de mano de obra, tal como el igualado o acabado de puntas. 4. Los artículos de este Capítulo, excepto los de las partidas 96.01 a 96.06 o 96.15, constituidos total o parcialmente por metal precioso, chapado de metal precioso (plaqué), piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas), o que lleven perlas finas (naturales)* o cultivadas, permanecen clasificados en este Capítulo. Sin embargo, también están comprendidos en este Capítulo los artículos de las partidas 96.01 a 96.06 o 96.15 con simples guarniciones o accesorios de mínima importancia de metal precioso, chapado de metal precioso (plaqué), de perlas finas (naturales)* o cultivadas o piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas). 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 357', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (97, 'Capítulo', NULL, 97, 'Varios', 'Notas. 1. Este Capítulo no comprende: a) los sellos (estampillas) de correo, timbres fiscales, enteros postales, demás artículos franqueados y análogos, sin obliterar, de la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (98, 'Capítulo', NULL, 98, 'Varios', 'Notas. 1. Los tratamientos arancelarios especiales establecidos en el presente Capítulo, sólo serán aplicables a las mercancías importadas de acuerdo a los requisitos y procedimientos que se establezcan en cada caso de conformidad con las normas que dicte el Ejecutivo Nacional. 2. Las mercancías comprendidas en el presente Capítulo quedarán clasificadas aquí, incluso si se encuentran descritas de manera más precisa o completa en otro Capítulo de este Arancel. SUBCAPÍTULO I PARTES, PIEZAS Y COMPONENTES PARA EL ENSAMBLAJE DE VEHÍCULOS AUTOMOTORES, MOTOCICLETAS, TRACTORES, MOTOCULTORES, REMOLQUES Y SEMIREMOLQUES Notas de Subcapítulo: 1. El Subcapítulo I tiene por objeto, otorgar la clasificación arancelaria y autorizar la importación de partes, piezas y componentes para el ensamblaje de vehículos automotores, motocicletas, tractores, motocultores, remolques y semiremolques, bajo el régimen “Material de Ensamblaje Importado para Vehículos (MEIV)”, destinados a la producción nacional, de conformidad con los niveles previstos en las normas para el funcionamiento de la industria automotriz que a tal efecto haya dictado el Ejecutivo Nacional a través del órgano oficial competente. 2. A los efectos de la importación del Material de Ensamblaje Importado para Vehículos (MEIV) clasificado en el presente Subcapítulo, sólo podrán ingresar al Territorio Nacional partes, piezas y componentes nuevas y sin uso. 3. La clasificación de las mercancías comprendidas en el presente Subcapítulo se efectuará mediante el oficio de autorización bajo el Régimen de Material de Ensamblaje Importado para Vehículos (MEIV), otorgado por la dependencia competente del Servicio Nacional Integrado de Administración Aduanera y Tributaria (SENIAT). No formarán parte del Oficio de Autorización de Material de Ensamblaje Importado para Vehículos y en consecuencia serán excluidos de las listas presentadas, los repuestos, herramientas, resinas, pegamentos, ceras, aceites, grasas, lubricantes, alfombras y similares. La autorización bajo el Régimen de Material de Ensamblaje Importado para Vehículos (MEIV), será otorgada bajo las siguientes condiciones: a) El ingreso de la totalidad de las partes, piezas y componentes deberá realizarse en la forma y en los términos bajo los cuales se certifica en la lista correspondiente, la cual estará anexa a la autorización. b) La importación de las mercancías solamente podrá efectuarse por la oficina aduanera indicada en la autorización, salvo cuando concurran razones de fuerza mayor que así lo ameriten. c) Durante el lapso de vigencia, la autorización podrá ser objeto de modificaciones que amplíen el alcance de la misma (inclusión de material inicialmente excluido o de nuevas partes no incorporadas en el oficio original, cambio del número de partes). En ningún caso, las modificaciones efectuadas a la autorización podrán alterar la clasificación arancelaria inicialmente otorgada o la vigencia de la misma. d) No podrá ser transferida a terceros, deberá ser utilizada exclusivamente para los fines bajo los cuales fuera concebida. El incumplimiento de las condiciones bajo las cuales fuera concedida la autorización bajo el Régimen de Material de Ensamblaje Importado para Vehículos (MEIV), acarreará la imposición de la multa establecida en el artículo 172 del Decreto Constituyente mediante el cual se dicta la Ley Orgánica de Aduanas. 4. La importación de Material de Ensamblaje Importado para Vehículos (MEIV), deberá estar amparada por el Certificado de Emisiones de Fuentes Móviles, el cual deberá ser presentado junto con la respectiva Declaración de Aduanas, de conformidad con lo establecido en el Decreto N° 2.673 de fecha 19 de agosto de 1998, publicado en la Gaceta Oficial N° 36.532 en fecha 04 de septiembre de 1998, mediante el cual se establecen las Normas para el Control de las Emisiones de Escape y de las Emisiones Evaporativas provenientes de las Fuentes Móviles y en Resolución N° 334 de fecha 30 de noviembre de 1998, emanada del Ministerio del Ambiente y de los Recursos Naturales Renovables, publicada en la Gaceta Oficial N° 36.594 en fecha 02 de diciembre de 1998, mediante la cual se dictan las Normas relativas a la Certificación de Emisiones Provenientes de Fuentes Móviles. 5. A efectos de la importación del Material de Ensamblaje Importado para Vehículos (MEIV) clasificado en el presente Subcapítulo, que vengan equipados con sistemas de aire acondicionado, de enfriamiento o frigorífico (ambos inclusive), sólo podrán ingresar al Territorio Nacional, cuando dichas mercancías no contengan ni requieran para su funcionamiento productos hidroclorofluorocarbonados de la partida 29.03 o mezclas de estos producos de la partida 38.27, que estén afectados con Régimen Legal 1 “Importación Prohibida”. 6. Sin menoscabo de lo establecido en la Nota 3 anterior, las importaciones de mercancías clasificadas en las partidas de este Subcapítulo, realizadas por las personas jurídicas cuya actividad económica se corresponda con el sector automotriz, podrán ser objeto de exoneración del Arancel Externo Común fijado en la columna tres (3), así como del Impuesto al Valor Agregado (IVA), en los casos que se indican a continuación: a) Cuando el “Oficio de Calificación de Material de Ensamblaje importado para vehículos (MEIV)” emanado del Ministerio del Poder Popular con competencia en materia de industrias y producción nacional indique expresamente la exoneración del Arancel Externo Común (AEC) y/o del Impuesto al Valor Agregado (IVA) en el caso de las mercancías clasificadas en las partidas 98.01 a 98.07; o b) En los términos y condiciones previstos en el respectivo “Certificado de Exoneración del sector Automotriz” emanado del Ministerio del Poder Popular con competencia en materia de industrias y producción nacional, en el caso de la partida 98.08. La duración de la exoneración del impuesto al valor agregado señalada en esta Nota de Subcapítulo estará sujeta a la vigencia de los beneficios tributarios establecidos en el Decreto de Exoneraciones en Materia Aduanera, conforme a lo dispuesto en el artículo 75 del Decreto Constituyente mediante el cual se dicta e', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1001, 'Sección', 1, NULL, 'Varios', 'Notas. 1. En esta Sección, cualquier referencia a un género o a una especie determinada de un animal se aplica también, salvo disposición en contrario, a los animales jóvenes de ese género o de esa especie. 2. Salvo disposición en contrario, cualquier referencia en la Nomenclatura a productos secos o desecados alcanza también a los productos deshidratados, evaporados o liofilizados. Nota Complementaria. 1. En las subpartidas correspondientes a los Capítulos 1 y 3, las expresiones Reproductores de raza pura, para reproducción o cría industrial, para lidia y para carrera, comprenden los animales considerados como tales por la autoridad nacional competente.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1002, 'Sección', 2, NULL, 'Varios', 'Nota. 1. En esta Sección, el término «pellets» designa los productos en forma de cilindro, bolita, etc., aglomerados por simple presión o con adición de un aglutinante en proporción inferior o igual al 3 % en peso. Nota Complementaria. 1. Con excepción de lo señalado en la Nota 3 del Capítulo 12, en las subpartidas correspondientes de esta Sección, la expresión «para siembra» comprende solamente los productos considerados como tales por la autoridad nacional competente.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1004, 'Sección', 4, NULL, 'Varios', 'Notas de Sección 16 Preparaciones de carne, pescado o de crustáceos, moluscos o demás invertebrados acuáticos, o de insectos. 17 Azúcares y artículos de confitería 18 Cacao y sus preparaciones 19 Preparaciones a base de cereales, harina, almidón, fécula o leche; productos de pastelería', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1006, 'Sección', 6, NULL, 'Varios', 'Notas. 1. A) Cualquier producto que responda al texto específico de una de las partidas 28.44 o 28.45, se clasifica en dicha partida y no en otra de la Nomenclatura, excepto los minerales de metales radiactivos. B) Salvo lo dispuesto en el apartado A) anterior, cualquier producto que responda al texto específico de una de las partidas 28.43, 28.46 o 28.52, se clasifica en dicha partida y no en otra de esta Sección. 2. Sin perjuicio de las disposiciones de la Nota 1 anterior, cualquier producto que, por su presentación en forma de dosis o por su acondicionamiento para la venta al por menor, pueda incluirse en una de las partidas 30.04, 30.05, 30.06, 32.12, 33.03, 33.04, 33.05, 33.06, 33.07, 35.06, 37.07 o 38.08, se clasifica en dicha partida y no en otra de la Nomenclatura. 3. Los productos presentados en surtidos que consistan en varios componentes distintos comprendidos, en su totalidad o en parte, en esta Sección e identificables como destinados, después de mezclados, a constituir un producto de las Secciones VI o VII, se clasifican en la partida correspondiente a este último producto siempre que los componentes sean: a) netamente identificables, por su acondicionamiento, como destinados a utilizarse juntos sin previo reacondicionamiento; b) presentados simultáneamente; c) identificables, por su naturaleza o por sus cantidades respectivas, como complementarios unos de otros. 4. Cuando un producto responda a las especificaciones de una o más de las partidas de la Sección VI, por el hecho de que en ellas se mencione su nombre o función y también responda a las especificaciones de la partida 38.27, se clasifica en la partida cuyo texto mencione su nombre o función y no en la partida', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1007, 'Sección', 7, NULL, 'Varios', 'Notas. 1. Los productos presentados en surtidos que consistan en varios componentes distintos comprendidos, en su totalidad o en parte, en esta Sección e identificables como destinados, después de mezclados, a constituir un producto de las Secciones VI o VII, se clasifican en la partida correspondiente a este último producto siempre que los componentes sean: a) por su acondicionamiento, netamente identificables como destinados a utilizarse juntos sin previo reacondicionamiento; b) presentados simultáneamente; c) identificables, por su naturaleza o por sus cantidades respectivas, como complementarios unos de otros. 2. El plástico, el caucho y las manufacturas de estas materias, con impresiones o ilustraciones que no tengan un carácter accesorio en relación con su utilización principal, corresponden al Capítulo 49, excepto los artículos de las partidas 39.18 o 39.19.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1011, 'Sección', 11, NULL, 'Varios', 'Notas. 1. Esta Sección no comprende: a) los pelos y cerdas para cepillería (partida 05.02), la crin y los desperdicios de crin (partida 05.11); b) el cabello y sus manufacturas (partidas 05.01, 67.03 o 67.04); sin embargo, las telas filtrantes, capachos y telas gruesas, de cabello, de los tipos utilizados comúnmente en las prensas de aceite o en usos técnicos análogos, se clasifican en la partida 59.11; c) los línteres de algodón y demás productos vegetales del Capítulo 14; d) el amianto (asbesto) de la partida 25.24 y los artículos de amianto y demás productos de las partidas 68.12 o 68.13; e) los artículos de las partidas 30.05 o 30.06; el hilo utilizado para limpieza de los espacios interdentales (hilo dental), en envases individuales acondicionados para la venta al por menor, de la partida 33.06; f) los textiles sensibilizados de las partidas 37.01 a 37.04; g) los monofilamentos cuya mayor dimensión de la sección transversal sea superior a 1 mm y las tiras y formas similares (por ejemplo, paja artificial) de anchura aparente superior a 5 mm, de plástico (Capítulo 39), así como las trenzas, tejidos y demás manufacturas de espartería o cestería de estos mismos artículos (Capítulo 46); h) los tejidos, incluso de punto, fieltro y tela sin tejer, impregnados, recubiertos, revestidos o estratificados con plástico y los artículos de estos productos, del Capítulo 39; ij) los tejidos, incluso de punto, fieltro y tela sin tejer, impregnados, recubiertos, revestidos o estratificados con caucho y los artículos de estos productos, del Capítulo 40; k) las pieles sin depilar (Capítulos 41 o 43) y los artículos de peletería natural o de peletería facticia o artificial de las partidas 43.03 o 43.04; l) los artículos de materia textil de las partidas 42.01 o 42.02; m) los productos y artículos del Capítulo 48 (por ejemplo, la guata de celulosa); n) el calzado y sus partes, polainas y artículos similares, del Capítulo 64; o) las redecillas para el cabello y los sombreros y demás tocados, y sus partes, del Capítulo 65; p) los productos del Capítulo 67; q) los productos textiles recubiertos de abrasivos (partida 68.05), así como las fibras de carbono y las manufacturas de estas fibras, de la partida 68.15; r) las fibras de vidrio, los artículos de fibras de vidrio y los bordados químicos o sin fondo visible con hilo bordador de fibras de vidrio (Capítulo 70); s) los artículos del Capítulo 94 (por ejemplo: muebles, artículos de cama, luminarias y aparatos de alumbrado); t) los artículos del Capítulo 95 (por ejemplo: juguetes, juegos, artefactos deportivos, redes para deportes); u) los artículos del Capítulo 96 (por ejemplo: cepillos y brochas, juegos o surtidos de viaje para costura, cierres de cremallera (cierres relámpago), cintas entintadas para máquinas de escribir, compresas y tampones higiénicos, pañales); v) los artículos del Capítulo 97. 1º) 85 g para los hilados de seda, de desperdicios de seda o de filamentos sintéticos o artificiales; o 2º) 125 g para los demás hilados; b) en bolas, ovillos, madejas o madejitas, con un peso inferior o igual a: 1º) 85 g para los hilados de filamentos sintéticos o artificiales, de título inferior a 3.000 decitex, de seda o de desperdicios de seda; o 2º) 125 g para los demás hilados de título inferior a 2.000 decitex; o 3º) 500 g para los demás hilados; c) en madejas subdivididas en madejitas por medio de uno o varios hilos divisores que las hacen independientes unas de otras, con un peso uniforme por cada madejita inferior o igual a: 1º) 85 g para los hilados de seda, de desperdicios de seda o de filamentos sintéticos o artificiales; o 2º) 125 g para los demás hilados. B) Las disposiciones anteriores no se aplican: a) a los hilados sencillos de cualquier materia textil, excepto: 1º) los hilados sencillos de lana o pelo fino, crudos; y 2º) los hilados sencillos de lana o pelo fino, blanqueados, teñidos o estampados, de título superior a 5.000 decitex; b) a los hilados crudos, retorcidos o cableados: 1º) de seda o de desperdicios de seda, cualquiera que sea su forma de presentación; o 2º) de las demás materias textiles (excepto lana y pelo fino) que se presenten en madejas; c) a los hilados de seda o de desperdicios de seda, retorcidos o cableados, blanqueados, teñidos o estampados, de título inferior o igual a 133 decitex; d) a los hilados sencillos, retorcidos o cableados, de cualquier materia textil, que se presenten: 1º) en madejas de devanado cruzado; o 2º) con soporte u otro acondicionamiento que implique su utilización en la industria textil (por ejemplo: en tubos de máquinas para el retorcido, canillas, husos cónicos o conos, en madejas para máquinas de bordar). 5. En las partidas 52.04, 54.01 y 55.08, se entiende por hilo de coser, el hilado retorcido o cableado que satisfaga todas las condiciones siguientes: a) que se presente en soportes (por ejemplo: carretes, tubos) de peso inferior o igual a 1.000 g, incluido el soporte; b) aprestado para su utilización como hilo de coser; y c) con torsión final «Z». 6. En esta Sección, se entiende por hilados de alta tenacidad, los hilados cuya tenacidad, expresada en cN/tex (centinewton por tex), sea superior a los límites siguientes: Hilados sencillos de nailon o demás poliamidas o de poliésteres…..................................60 cN/tex hilados retorcidos o cableados de nailon o demás poliamidas o de poliésteres…… …53 cN/tex hilados sencillos, retorcidos o cableados de rayón viscosa.…….................................... 27 cN/tex 7. En esta Sección, se entiende por confeccionados: a) los artículos cortados en forma distinta de la cuadrada o rectangular; b) los artículos terminados directamente y listos para su uso o que puedan utilizarse después de haber sido separados por simple corte de los hilos sin entrelazar, sin costuras ni otra mano de obra complementaria, tales como algunos paños de cocina, toallas, manteles, pañuelos de cuello y mantas; c) los artículos cortados en las dimensiones requeridas en los que al menos uno de sus bordes haya sido termosellado, con el borde visiblemente adelgazado o comprimido y los demás bordes tratados según los procedimientos descritos en los demás apartados de esta Nota; sin embargo, no se considera confeccionada la materia textil en piezas cuyos bordes desprovistos de orillos hayan sido cortados en caliente o simplemente sobrehilados para evitar su deshilachado; d) los artículos cuyos bordes hayan sido dobladillados o ribeteados por cualquier sistema o sujetados por medio de flecos anudados obtenidos con hilos del propio artículo o con hilos aplicados; sin embargo, no se considera confeccionada la materia textil en pieza cuyos bordes desprovistos de orillos hayan sido simplemente sujetados; e) los artículos cortados en cualquier forma, que hayan sido objeto de un trabajo de entresacado de hilos; f) los artículos unidos por costura, pegado u otra forma (excepto las piezas de un mismo textil unidas por sus extremos para formar una pieza de mayor longitud, así como las piezas constituidas por dos o más textiles superpuestos en toda su superficie y unidas de esta forma, incluso con interposición de materia de relleno); g) los artículos de punto obtenidos con forma determinada, que se presenten en unidades o en pieza que comprenda varias unidades. 8. A los efectos de los Capítulos 50 a 60: a) no se clasifican en los Capítulos 50 a 55 y 60 ni, salvo disposición en contrario, en los Capítulos 56 a 59, los artículos confeccionados tal como se definen en la Nota 7 anterior; b) no se clasifican en los Capítulos 50 a 55 y 60 los artículos de los Capítulos 56 a 59. 9. Los productos constituidos por napas de hilados textiles paralelizados que se superponen en ángulo recto o agudo se asimilarán a los tejidos de los Capítulos 50 a 55. Estas napas se fijan entre sí en los puntos de cruce de sus hilados mediante un adhesivo o por termosoldado. 10. Los productos elásticos constituidos por materia textil combinada con hilos de caucho se clasifican en esta Sección. 11. En esta Sección, el término impregnado abarca también el adherizado. 12. En esta Sección, el término poliamidas abarca también las aramidas. 13. En esta Sección y, en su caso, en la Nomenclatura, se entiende por hilados de elastómeros, los hilados de filamentos (incluidos los monofilamentos) de materia textil sintética, excepto los hilados texturados, que puedan alargarse hasta tres veces su longitud primitiva sin romperse y que, después de alargarse hasta dos veces su longitud primitiva, adquieran, en menos de cinco minutos, una longitud inferior o igual a una vez y media su longitud primitiva. 14. Salvo disposición en contrario, las prendas de vestir de materia textil que pertenezcan a partidas distintas se clasifican en sus partidas respectivas, incluso si se presentan en surtidos para la venta al por menor. A los efectos de esta Nota, se entiende por prendas de vestir de materia textil las prendas de las partidas 61.01 a 61.14 y de las partidas 62.01 a 62.11. 15. Salvo lo dispuesto en la Nota 1 de la Sección XI, los textiles, prendas de vestir y demás artículos textiles, que incorporen componentes químicos, mecánicos o electrónicos para agregarles funcionalidad, ya sea incorporados como componentes integrados o en el interior de la fibra o tejido, se clasifican en sus respectivas partidas de la Sección XI, siempre que conserven el carácter esencial de artículos de esta Sección. Notas de subpartida. 1. En esta Sección y, en su caso, en la Nomenclatura, se entiende por: a) Hilados crudos los hilados: 1º) con el color natural de las fibras que los constituyan, sin blanquear, teñir (incluso en la masa) ni estampar; o 2º) sin color bien determinado (hilados «grisáceos») fabricados con hilachas. Estos hilados pueden tener un apresto sin colorear o un color fugaz (el color fugaz desaparece por simple lavado con jabón) y, en el caso de fibras sintéticas o artificiales, estar tratados en la masa con productos de mateado (por ejemplo, dióxido de titanio). b) Hilados blanqueados los hilados: 1º) blanqueados o fabricados con fibras blanqueadas o, salvo disposición en contrario, teñidos de blanco (incluso en la masa) o con apresto blanco; o 2º) constituidos por una mezcla de fibras crudas con fibras blanqueadas; o 3º) retorcidos o cableados, constituidos por hilados crudos e hilados blanqueados. c) Hilados coloreados (teñidos o estampados) los hilados: 1º) teñidos (incluso en la masa), excepto de blanco o un color fugaz, o bien estampados o fabricados con fibras teñidas o estampadas; o 2º) constituidos por una mezcla de fibras teñidas de color diferente o por una mezcla de fibras crudas o blanqueadas con fibras coloreadas (hilados jaspeados o mezclados) o estampados a trechos con uno o varios colores, con aspecto de puntillado; o 3º) en los que la mecha o «roving» de materia textil haya sido estampada; o 4º) retorcidos o cableados, constituidos por hilados crudos o blanqueados e hilados coloreados. Las definiciones anteriores se aplican también, mutatis mutandis, a los monofilamentos y a las tiras o formas similares del Capítulo 54. d) Tejidos crudos los tejidos de hilados crudos sin blanquear, teñir ni estampar. Estos tejidos pueden tener un apresto sin color o un color fugaz. e) Tejidos blanqueados los tejidos: 1º) blanqueados o, salvo disposición en contrario, teñidos de blanco o con apresto blanco, en pieza; o 2º) constituidos por hilados blanqueados; o 3º) constituidos por hilados crudos e hilados blanqueados. f) Tejidos teñidos los tejidos: 1º) teñidos en pieza con un solo color uniforme, excepto el blanco (salvo disposición en contrario) o con apresto coloreado, excepto el blanco (salvo disposición en contrario); o 2º) constituidos por hilados coloreados con un solo color uniforme. g) Tejidos con hilados de distintos colores los tejidos (excepto los tejidos estampados): 1º) constituidos por hilados de colores distintos o por hilados de matiz diferente de un mismo color, distintos del color natural de las fibras constitutivas; o 2º) constituidos por hilados crudos o blanqueados e hilados coloreados; o 6.804 Extraordinario GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 195', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1015, 'Sección', 15, NULL, 'Varios', 'Notas de Sección 72 Fundición, hierro y acero 73 Manufacturas de fundición, hierro o acero 74 Cobre y sus manufacturas 75 Níquel y sus manufacturas 76 Aluminio y sus manufacturas 77 (Reservado para una futura utilización en el Sistema Armonizado) 78 Plomo y sus manufacturas 79 Cinc y sus manufacturas 80 Estaño y sus manufacturas 81 Los demás metales comunes; cermets; manufacturas de estas materias 82 Herramientas y útiles, artículos de cuchillería y cubiertos de mesa, de metal común; partes de estos artículos, de metal común 83 Manufacturas diversas de metal común', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1016, 'Sección', 16, NULL, 'Varios', 'Notas. 1. Esta Sección no comprende: a) las correas transportadoras o de transmisión de plástico del Capítulo 39, o de caucho vulcanizado (partida 40.10) y demás artículos de los tipos utilizados en máquinas o aparatos mecánicos o eléctricos o para otros usos técnicos, de caucho vulcanizado sin endurecer (partida 40.16); b) los artículos para usos técnicos de cuero natural o cuero regenerado (partida 42.05) o de peletería (partida 43.03); c) las canillas, carretes, bobinas y soportes similares, de cualquier materia (por ejemplo: Capítulos 39, 40, 44 o 48 o Sección XV); d) las tarjetas perforadas para mecanismos Jacquard o máquinas similares (por ejemplo: Capítulos 39 o 48 o Sección XV); e) las correas transportadoras o de transmisión, de materia textil (partida 59.10), así como los artículos para usos técnicos de materia textil (partida 59.11); f) las piedras preciosas o semipreciosas (naturales, sintéticas o reconstituidas) de las partidas 71.02 a 71.04, así como las manufacturas constituidas totalmente por estas materias, de la partida 71.16, excepto, sin embargo, los zafiros y diamantes, trabajados, sin montar, para agujas de fonocaptores (partida 85.22); g) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV) y los artículos similares de plástico (Capítulo 39); h) los tubos de perforación (partida 73.04); ij) las telas y correas sin fin, de alambre o tiras metálicos (Sección XV); k) los artículos de los Capítulos 82 u 83; l) los artículos de la Sección XVII; m) los artículos del Capítulo 90; n) los artículos de relojería (Capítulo 91); o) los útiles intercambiables de la partida 82.07 y los cepillos que constituyan partes de máquinas (partida 96.03); los útiles intercambiables similares que se clasifican según la materia constitutiva de la parte operante (por ejemplo: Capítulos 40, 42, 43, 45 o 59, o partidas 68.04 o 69.09); p) los artículos del Capítulo 95; q) las cintas para máquina de escribir y cintas entintadas similares, incluso en carretes o cartuchos (clasificación según la materia constitutiva o en la partida 96.12 si están entintadas o preparadas de otro modo para imprimir), así como los monopies, bípodes, trípodes y artículos similares, de la partida 96.20. 2. Salvo lo dispuesto en la Nota 1 de esta Sección y en la Nota 1 de los Capítulos 84 y 85, las partes de máquinas (excepto las partes de los artículos comprendidos en las partidas 84.84, 85.44, 85.45, 85.46 u 85.47) se clasifican de acuerdo con las siguientes reglas: a) las partes que consistan en artículos de cualquier partida de los Capítulos 84 u 85 (excepto las partidas 84.09, 84.31, 84.48, 84.66, 84.73, 84.87, 85.03,', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1017, 'Sección', 17, NULL, 'Varios', 'Notas. 1. Esta Sección no comprende los artículos de las partidas 95.03 o 95.08 ni los toboganes, «bobsleighs» y similares (partida 95.06). 2. No se consideran partes o accesorios de material de transporte, aunque sean identificables como tales: a) las juntas o empaquetaduras, arandelas y similares, de cualquier materia (régimen de la materia constitutiva o partida 84.84), así como los demás artículos de caucho vulcanizado sin endurecer (partida 40.16); b) las partes y accesorios de uso general, tal como se definen en la Nota 2 de la Sección XV, de metal común (Sección XV), ni los artículos similares de plástico (Capítulo 39); c) los artículos del Capítulo 82 (herramientas); d) los artículos de la partida 83.06; e) las máquinas y aparatos de las partidas 84.01 a 84.79, así como sus partes, excepto los radiadores para los vehículos de la Sección XVII; los artículos de las partidas 84.81 u 84.82 y, siempre que constituyan partes intrínsecas de motor, los artículos de la partida 84.83; f) las máquinas y aparatos eléctricos, así como el material eléctrico (Capítulo 85); g) los instrumentos y aparatos del Capítulo 90; h) los artículos del Capítulo 91; ij) las armas (Capítulo 93); k) las luminarias y los aparatos de alumbrado y sus partes, de la partida 94.05; l) los cepillos que constituyan partes de vehículos (partida 96.03). 3. En los Capítulos 86 a 88, la referencia a las partes o a los accesorios no abarca a las partes o accesorios que no estén destinados, exclusiva o principalmente, a los vehículos o artículos de esta Sección. Cuando una parte o un accesorio sea susceptible de responder a las especificaciones de dos o más partidas de la Sección, se clasifica en la partida que corresponda a su utilización principal. 4. En esta Sección: a) los vehículos especialmente diseñados para ser utilizados en carretera y sobre carriles (rieles), se clasifican en la partida apropiada del Capítulo 87; b) los vehículos automóviles anfibios se clasifican en la partida apropiada del Capítulo 87; c) las aeronaves especialmente diseñadas para ser utilizadas también como vehículos terrestres, se clasifican en la partida apropiada del Capítulo 88. 5. Los vehículos de cojín (colchón) de aire se clasifican con los vehículos con los que guarden mayor analogía: a) del Capítulo 86, si están diseñados para desplazarse sobre una vía guía (aerotrenes); b) del Capítulo 87, si están diseñados para desplazarse sobre tierra firme o indistintamente sobre tierra firme o sobre agua; c) del Capítulo 89, si están diseñados para desplazarse sobre agua, incluso aunque pueden posarse en playas o embarcaderos o desplazarse también sobre superficies heladas. Las partes y accesorios de vehículos de cojín (colchón) de aire se clasifican igual que las partes y accesorios de los vehículos de la partida en que éstos se hubieran clasificado por aplicación de las disposiciones anteriores. 326 GACETA OFICIAL DE LA REPÚBLICA BOLIVARIANA DE VENEZUELA 6.804 Extraordinario', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1018, 'Sección', 18, NULL, 'Varios', 'Nota Complementaria. 1. A los efectos de la importación de instrumentos clasificados en las partidas de los Capítulos 90 ó 91 de esta Sección, provistos de aeronaves no tripuladas, sólo podrán ingresar a Territorio Nacional aquellos que dispongan del comprobante electrónico de Declaración de Ingreso de Aeronave Pilotada a Distancia (RPA), otorgado por la autoridad aeronáutica, el cual deberá ser presentado junto a la respectiva Declaración de Aduanas.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO notas_legales (id_notas_legales, nivel_nota, id_seccion, id_capitulo, numero_nota, texto_nota, created_at, updated_at) VALUES (1020, 'Sección', 20, NULL, 'Varios', 'Nota Complementaria. 1. A los efectos de la importación de mercancías clasificadas en las partidas de los Capítulos 94, 95 o 96 de esta Sección, provistas de vehículos aéreos no tripulados «Drones», sólo podrán ingresar a Territorio Nacional aquellos que dispongan del comprobante electrónico de Declaración de Ingreso de RPA, otorgado por la autoridad aeronáutica, el cual deberá ser presentado junto a la respectiva Declaración de Aduanas.', '2026-05-10 00:00:00', '2026-05-10 00:00:00');
INSERT INTO partidas (id_partida, id_capitulo, codigo, descripcion, created_at, updated_at) VALUES (1, 1, 0101, 'CABALLOS, ASNOS, MULOS Y BURDÉGANOS, VIVOS.', '2026-05-09 15:10:03', '2026-05-09 15:10:03');
