INSERT INTO partidas (id_partida, id_capitulo, codigo, descripcion, created_at, updated_at) VALUES (1102, 87, 8704, '(excepto: 8704.10.10.00 y 8704.10.90.00), 87.06 (excepto: 8706.00.20.00), 87.07 (excepto: 8707.90.90.10 y 8707.90.90.90), 87.11 y 87.16 (excepto: 8716.10.00.00, 8716.80.00.10, 8716.80.00.90, 8716.90.10.00 y 8716.90.90.00), sólo podrán ingresar al Territorio Nacional, unidades nuevas y sin uso de cualquier marca y modelo, siempre que el año modelo que asigna el fabricante o el año de fabricación coincida con el año en que se realice la importación o con años subsiguientes. La introducción de vehículos automóviles bajo los Regímenes de Equipaje de Pasajeros y de Admisión Temporal, se regirá por las normas que a tal efecto haya dictado el Ministerio del Poder Popular con competencia en materia de Finanzas.', '2026-05-09 15:10:03', '2026-05-09 15:10:03');
