INSERT INTO partidas (id_partida, id_capitulo, codigo, descripcion, created_at, updated_at) VALUES (1104, 87, 8705, 'y 87.06 deberá estar amparada por la Conformidad del Certificado de Emisiones de Fuentes Móviles, otorgada por el Ministerio del Poder Popular con competencia en materia de Ambiente y de tratarse de importación de vehículos automóviles desprovistos de motor, la misma deberá estar amparada únicamente por el Certificado de Emisiones de Fuentes Móviles, en ambos casos, tales requisitos deberán ser presentados junto a la respectiva Declaración de Aduanas, de conformidad con lo prescrito en el Decreto Nº 2.673 de fecha 19 agosto de 1998, publicado en la Gaceta Oficial Nº 36.532 en fecha 04 de septiembre de 1998, mediante el cual se establecen las Normas para el Control de las Emisiones de Escape y de las Emisiones Evaporativas provenientes de las Fuentes Móviles; así como lo establecido en la Resolución Nº 334 de fecha 30 de noviembre de 1998, emanada del Ministerio del Ambiente y de los Recursos Naturales Renovables, publicada en la Gaceta Oficial Nº 36.594 en fecha 02 de diciembre de', '2026-05-09 15:10:03', '2026-05-09 15:10:03');
