BEGIN;

DROP TABLE IF EXISTS subpartidas;
DROP TABLE IF EXISTS partidas;
DROP TABLE IF EXISTS notas_legales;
DROP TABLE IF EXISTS capitulos;
DROP TABLE IF EXISTS secciones;

CREATE TABLE secciones (
    id_seccion INT PRIMARY KEY,
    numero_seccion VARCHAR(10),
    descripcion TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE capitulos (
    id_capitulo INT PRIMARY KEY,
    id_seccion INT REFERENCES secciones(id_seccion),
    numero_capitulo VARCHAR(10),
    descripcion TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE notas_legales (
    id_notas_legales INT PRIMARY KEY,
    nivel_nota VARCHAR(20),
    id_seccion INT REFERENCES secciones(id_seccion),
    id_capitulo INT REFERENCES capitulos(id_capitulo),
    numero_nota VARCHAR(50),
    texto_nota TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE partidas (
    id_partida INT PRIMARY KEY,
    id_capitulo INT REFERENCES capitulos(id_capitulo),
    codigo NUMERIC,
    descripcion TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE subpartidas (
    id_subpartida INT PRIMARY KEY,
    id_partida INT REFERENCES partidas(id_partida),
    codigo NUMERIC,
    descripcion TEXT,
    aec VARCHAR(20),
    ex_aec VARCHAR(20),
    imp VARCHAR(255),
    exp VARCHAR(255),
    unidad VARCHAR(20),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


COMMIT;
